import{_ as d,o as p,c as r,a2 as o}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"伯克希尔·哈撒韦公司2014年致股东信","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2014年/翻译.md","filePath":"01_letters/2014年/翻译.md"}'),a={name:"01_letters/2014年/翻译.md"};function n(s,t,e,u,h,q){return p(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="伯克希尔·哈撒韦公司2014年致股东信" tabindex="-1">伯克希尔·哈撒韦公司2014年致股东信 <a class="header-anchor" href="#伯克希尔·哈撒韦公司2014年致股东信" aria-label="Permalink to &quot;伯克希尔·哈撒韦公司2014年致股东信&quot;">​</a></h1><hr><h2 id="伯克希尔业绩与标普500对比" tabindex="-1">伯克希尔业绩与标普500对比 <a class="header-anchor" href="#伯克希尔业绩与标普500对比" aria-label="Permalink to &quot;伯克希尔业绩与标普500对比&quot;">​</a></h2><p><strong>年度百分比变化</strong></p><table tabindex="0"><thead><tr><th>年份</th><th>每股账面价值</th><th>每股市场价值</th><th>标普500（含股息）</th></tr></thead><tbody><tr><td>1965</td><td>23.8</td><td>49.5</td><td>10.0</td></tr><tr><td>1966</td><td>20.3</td><td>(3.4)</td><td>(11.7)</td></tr><tr><td>1967</td><td>11.0</td><td>13.3</td><td>30.9</td></tr><tr><td>1968</td><td>19.0</td><td>77.8</td><td>11.0</td></tr><tr><td>1969</td><td>16.2</td><td>19.4</td><td>(8.4)</td></tr><tr><td>1970</td><td>12.0</td><td>(4.6)</td><td>3.9</td></tr><tr><td>1971</td><td>16.4</td><td>80.5</td><td>14.6</td></tr><tr><td>1972</td><td>21.7</td><td>8.1</td><td>18.9</td></tr><tr><td>1973</td><td>4.7</td><td>(2.5)</td><td>(14.8)</td></tr><tr><td>1974</td><td>5.5</td><td>(48.7)</td><td>(26.4)</td></tr><tr><td>1975</td><td>21.9</td><td>2.5</td><td>37.2</td></tr><tr><td>1976</td><td>59.3</td><td>129.3</td><td>23.6</td></tr><tr><td>1977</td><td>31.9</td><td>46.8</td><td>(7.4)</td></tr><tr><td>1978</td><td>24.0</td><td>14.5</td><td>6.4</td></tr><tr><td>1979</td><td>35.7</td><td>102.5</td><td>18.2</td></tr><tr><td>1980</td><td>19.3</td><td>32.8</td><td>32.3</td></tr><tr><td>1981</td><td>31.4</td><td>31.8</td><td>(5.0)</td></tr><tr><td>1982</td><td>40.0</td><td>38.4</td><td>21.4</td></tr><tr><td>1983</td><td>32.3</td><td>69.0</td><td>22.4</td></tr><tr><td>1984</td><td>13.6</td><td>(2.7)</td><td>6.1</td></tr><tr><td>1985</td><td>48.2</td><td>93.7</td><td>31.6</td></tr><tr><td>1986</td><td>26.1</td><td>14.2</td><td>18.6</td></tr><tr><td>1987</td><td>19.5</td><td>4.6</td><td>5.1</td></tr><tr><td>1988</td><td>20.1</td><td>59.3</td><td>16.6</td></tr><tr><td>1989</td><td>44.4</td><td>84.6</td><td>31.7</td></tr><tr><td>1990</td><td>7.4</td><td>(23.1)</td><td>(3.1)</td></tr><tr><td>1991</td><td>39.6</td><td>35.6</td><td>30.5</td></tr><tr><td>1992</td><td>20.3</td><td>29.8</td><td>7.6</td></tr><tr><td>1993</td><td>14.3</td><td>38.9</td><td>10.1</td></tr><tr><td>1994</td><td>13.9</td><td>25.0</td><td>1.3</td></tr><tr><td>1995</td><td>43.1</td><td>57.4</td><td>37.6</td></tr><tr><td>1996</td><td>31.8</td><td>6.2</td><td>23.0</td></tr><tr><td>1997</td><td>34.1</td><td>34.9</td><td>33.4</td></tr><tr><td>1998</td><td>48.3</td><td>52.2</td><td>28.6</td></tr><tr><td>1999</td><td>0.5</td><td>(19.9)</td><td>21.0</td></tr><tr><td>2000</td><td>6.5</td><td>26.6</td><td>(9.1)</td></tr><tr><td>2001</td><td>(6.2)</td><td>6.5</td><td>(11.9)</td></tr><tr><td>2002</td><td>10.0</td><td>(3.8)</td><td>(22.1)</td></tr><tr><td>2003</td><td>21.0</td><td>15.8</td><td>28.7</td></tr><tr><td>2004</td><td>10.5</td><td>4.3</td><td>10.9</td></tr><tr><td>2005</td><td>6.4</td><td>0.8</td><td>4.9</td></tr><tr><td>2006</td><td>18.4</td><td>24.1</td><td>15.8</td></tr><tr><td>2007</td><td>11.0</td><td>28.7</td><td>5.5</td></tr><tr><td>2008</td><td>(9.6)</td><td>(31.8)</td><td>(37.0)</td></tr><tr><td>2009</td><td>19.8</td><td>2.7</td><td>26.5</td></tr><tr><td>2010</td><td>13.0</td><td>21.4</td><td>15.1</td></tr><tr><td>2011</td><td>4.6</td><td>(4.7)</td><td>2.1</td></tr><tr><td>2012</td><td>14.4</td><td>16.8</td><td>16.0</td></tr><tr><td>2013</td><td>18.2</td><td>32.7</td><td>32.4</td></tr><tr><td>2014</td><td>8.3</td><td>27.0</td><td>13.7</td></tr></tbody></table><p><strong>复合年收益率——1965-2014年：</strong> 19.4% | 21.6% | 9.9%</p><p><strong>总收益——1964-2014年：</strong> 751,113% | 1,826,163% | 11,196%</p><p><strong>注：</strong> 数据为日历年，以下情况除外：1965年和1966年，年度截止于9月30日；1967年，15个月截止于12月31日。从1979年开始，会计准则要求保险公司将其持有的权益证券按市值而非之前的成本与市价孰低法计价。本表中，伯克希尔1978年及之前的结果已按变更后的准则重新表述。其他方面，结果均按原始报告数字计算。标普500数字为税前，而伯克希尔数字为税后。如果一家公司如伯克希尔仅仅持有标普500并计提相应税款，其结果将在指数正回报年份落后于标普500，但在指数负回报年份超越标普500。多年下来，税款成本将导致累计落后幅度相当可观。</p><hr><h2 id="致读者的说明" tabindex="-1">致读者的说明 <a class="header-anchor" href="#致读者的说明" aria-label="Permalink to &quot;致读者的说明&quot;">​</a></h2><p>五十年前，现任管理层接管了伯克希尔。为纪念这个金禧年，沃伦·巴菲特和查理·芒格各自撰写了对伯克希尔过去50年发生的看法，以及对未来50年的预期。两人读完对方的评论后，均未改动一字。沃伦的思考从第24页开始，查理的从第39页开始。股东们，尤其是新股东，可能会发现阅读这些信件有助于理解下面开始的2014年报告。</p><hr><h2 id="伯克希尔·哈撒韦公司" tabindex="-1">伯克希尔·哈撒韦公司 <a class="header-anchor" href="#伯克希尔·哈撒韦公司" aria-label="Permalink to &quot;伯克希尔·哈撒韦公司&quot;">​</a></h2><p><strong>致伯克希尔·哈撒韦公司股东：</strong></p><p>伯克希尔2014年净资产收益为183亿美元，使A类和B类股票的每股账面价值均增长8.3%。在过去50年里（即自现任管理层接管以来），每股账面价值从19美元增长至146,186美元，年复合增长率为19.4%。*</p><p>在我们任职期间，我们一直将标普500的年度业绩与伯克希尔每股账面价值的变化进行比较。我们这样做是因为账面价值虽然粗略，但却是追踪那个真正重要的数字——内在商业价值——的有用工具。</p><p>在我们早期的几十年里，账面价值与内在价值的关系比现在要密切得多。这是因为当时伯克希尔的资产主要是证券，其价值不断按当前市场价格重新表述。用华尔街的说法，计算账面价值所涉及的大部分资产都是&quot;盯市&quot;的。</p><p>如今，我们的重心已大幅转向拥有和经营大型企业。其中许多企业的价值远高于其成本基础账面价值。但无论这些公司的价值增长多少，该金额从未被重新估值上调。因此，伯克希尔的内在价值与其账面价值之间的差距已显著扩大。</p><p>考虑到这一点，我们在对面的业绩表中增加了一组新数据——伯克希尔股价的历史记录。让我强调一下，市场价格在短期内有其局限性。股票的月度或年度走势往往反复无常，并不能反映内在价值的变化。然而，随着时间的推移，股票价格与内在价值几乎必然趋于一致。伯克希尔副董事长兼我的合伙人查理·芒格和我相信，伯克希尔也是如此：在我们看来，伯克希尔过去50年每股内在价值的增长，大致等于公司股价1,826,163%的涨幅。</p><p>*本报告中使用的所有每股数字均适用于伯克希尔A类股票。B类股票的数字为A类所示数字的1/1500。</p><hr><h2 id="伯克希尔年度回顾" tabindex="-1">伯克希尔年度回顾 <a class="header-anchor" href="#伯克希尔年度回顾" aria-label="Permalink to &quot;伯克希尔年度回顾&quot;">​</a></h2><p>2014年对伯克希尔来说是各方面表现良好的一年，只有一个例外。以下是重要进展：</p><p>*<em>• 我们的&quot;动力五巨头&quot;——伯克希尔最大的五家非保险业务——2014年税前利润达到创纪录的124亿美元，比2013年增加16亿美元。</em> 这组神圣的公司包括伯克希尔哈撒韦能源公司（原中美洲能源）、BNSF铁路、IMC（我过去称之为Iscar）、路博润（Lubrizol）和Marmon集团。</p><p>十年前，这五家公司中只有伯克希尔哈撒韦能源归我们所有，当时盈利3.93亿美元。此后，我们以全现金方式收购了另外三家。在收购第五家BNSF时，我们以现金支付约70%的成本，其余部分发行伯克希尔股票，使流通股数增加6.1%。换言之，这五家公司在十年间为伯克希尔带来的120亿美元年度利润增长，仅伴随着轻微的股权稀释。这符合我们的目标：不仅要增加利润，还要确保每股收益的增长。</p><p>如果2015年美国经济继续改善，我们预计动力五巨头的利润也将有所提升。增幅可能达到10亿美元，部分原因是该集团已经完成或正在签约的补强型收购。</p><p><strong>• 我们2014年的坏消息同样来自这五巨头，且与利润无关。这一年，BNSF让许多客户失望。这些托运人依赖我们，服务失误会严重损害他们的业务。</strong></p><p>BNSF是伯克希尔最重要的非保险子公司。为改善其表现，我们将在2015年投入60亿美元用于厂房和设备。这一金额比任何其他铁路公司在单一年份的支出高出近50%，无论与收入、利润还是折旧费用相比，这都是一个真正非凡的数字。</p><p>尽管天气——尤其是去年的恶劣天气——总是给铁路公司带来各种运营问题，但我们的责任是采取一切必要措施将服务恢复到行业领先水平。这无法一蹴而就：提升系统能力所需的大量工程有时会在进行中干扰运营。然而，我们的大额支出最近开始显现成效。过去三个月，BNSF的运营指标较去年同期已显著改善。</p><p><strong>• 我们数十家较小的非保险企业去年盈利51亿美元，高于2013年的47亿美元。与动力五巨头一样，我们预计2015年将进一步增长。在这个群体中，有两家公司去年盈利在4亿至6亿美元之间，六家盈利在2.5亿至4亿美元之间，七家盈利在1亿至2.5亿美元之间。这个企业集合将在数量和利润上继续增长。我们的雄心永无止境。</strong></p><p><strong>• 伯克希尔庞大且不断增长的保险业务在2014年再次实现承保盈利——这已是连续第12年——并增加了浮存金。在这12年间，我们的浮存金——不属于我们但我们可以为伯克希尔利益进行投资的钱——从410亿美元增长到840亿美元。虽然这一增长和浮存金规模均未反映在伯克希尔的利润中，但浮存金产生了可观的投资收益，因为它使我们能够持有相应资产。</strong></p><p>*除非另有说明，本信以及本报告后面包含的&quot;金禧年&quot;信件中的所有利润均为税前数字。</p><p>与此同时，我们在12年期间累计承保利润达240亿美元，包括2014年实现的27亿美元。而这一切始于1967年我们以860万美元收购国民赔偿公司。</p><p><strong>• 当查理和我寻找新企业收购时，我们的许多子公司定期进行补强型收购。去年成果尤其丰硕：我们签约了31项补强收购，总成本预计78亿美元。这些交易的规模从40万美元到29亿美元不等。然而，最大的一笔收购——金霸王——要到今年下半年才会完成。届时它将被纳入Marmon集团的管理。</strong></p><p>查理和我鼓励补强收购，只要价格合理。（向我们提出的大多数交易都不合理。）它们将资本配置到与我们现有业务相契合的领域，并由我们的专家管理团队管理。这意味着我们不需要做更多工作，却能获得更多利润——这种组合令我们格外欣赏。未来几年我们将进行更多此类补强交易。</p><p><strong>• 两年前，我的朋友豪尔赫·保罗·雷曼邀请伯克希尔加入他的3G资本集团收购亨氏。我的肯定回答是一个无需思考的决定：我立刻明白，这种合伙关系无论从个人还是财务角度都会运作良好。事实确实如此。</strong></p><p>我并不羞于承认，亨氏在董事长亚历克斯·贝林和首席执行官贝尔纳多·海斯的管理下，远比由我负责时运营得更好。他们坚持极高的绩效标准，从不满足，即使其业绩远超竞争对手。</p><p>我们预计将与3G在更多活动中合作。有时我们的参与仅涉及融资角色，如汉堡王近期收购Tim Hortons的交易。然而，我们更倾向于作为永久股权合伙人（在某些情况下也为交易提供融资）。无论结构如何，与豪尔赫·保罗合作让我们感觉良好。</p><p>伯克希尔还与玛氏公司和Leucadia公司有良好的合作关系，我们可能会与它们或其他伙伴建立新的合作关系。我们参与任何联合活动，无论是作为融资还是股权合伙人，都将限于友好交易。</p><p><strong>• 10月，我们签约收购Van Tuyl汽车集团——一个由78家汽车经销商组成的集团，运营极为出色。集团老板拉里·范·图伊尔几年前与我相识。他当时决定，如果有一天要出售公司，伯克希尔应该是其归宿。我们的收购最近完成，现在我们是&quot;汽车人&quot;了。</strong></p><p>拉里和他的父亲塞西尔花了62年建立这个集团，采用了一种让所有当地经理成为所有者合伙人的策略。创造这种利益共同体被反复证明是成功的。Van Tuyl现在是全国第五大汽车集团，单店销售业绩出众。</p><p>近年来，杰夫·雷乔与拉里并肩工作，这种成功安排将继续。全国约有17,000家经销商，所有权转移始终需要相关汽车制造商批准。伯克希尔的任务是表现出色，使制造商欢迎我们进一步收购。如果我们做到这一点——并且能以合理价格收购经销商——我们将建立一个业务，其规模不久将数倍于Van Tuyl目前90亿美元的销售额。</p><p>收购Van Tuyl后，伯克希尔现在拥有9½家若独立运营将入选财富500强的公司（亨氏是那½家）。这意味着海里还有490½条鱼。我们的钓线已投放。</p><p><strong>• 我们的子公司2014年在厂房和设备上投入创纪录的150亿美元，远超其折旧费用的两倍。约90%的资金投入美国。虽然我们也会投资海外，但机会的主矿脉贯穿美国。迄今已发现的宝藏与尚未开采的相比微不足道。凭借纯粹的运气，查理和我出生在美国，我们永远感激这一出生意外带给我们的巨大优势。</strong></p><p><strong>• 伯克希尔年末员工总数——包括亨氏——达到创纪录的340,499人，比上年增加9,754人。我可以自豪地说，这一增长不包括总部（25人工作）的增加。没必要发疯。</strong></p><p><strong>• 伯克希尔去年增持了其&quot;四大&quot;投资——美国运通、可口可乐、IBM和富国银行——的每一项。我们购买了更多IBM股票（持股比例从2013年末的6.3%增至7.8%）。同时，可口可乐、美国运通和富国银行的股票回购提高了我们对每家公司的持股比例。我们在可口可乐的权益从9.1%增至9.2%，在美国运通的权益从14.2%增至14.8%，在富国银行的持股从9.2%增至9.4%。如果你认为十分之一个百分点不重要，想想这个数学：对这四家公司合计而言，我们持股比例每增加十分之一百分点，伯克希尔在其年度利润中的份额就增加5,000万美元。</strong></p><p>这四家被投资方拥有卓越的业务，由既有才能又以股东为导向的管理层运营。在伯克希尔，我们更愿意持有一家优秀公司的大量非控股股权，而不是持有一家平庸公司的100%股权。与其拥有整颗人造钻石，不如部分拥有希望钻石。</p><p>如果以伯克希尔年末持股为基准，&quot;四大&quot;2014年扣除终止经营业务前的利润中我们的份额为47亿美元（而仅三年前为33亿美元）。然而，在我们向您报告的利润中，我们仅计入收到的股息——去年约16亿美元。（同样，三年前股息为8.62亿美元。）但请不要误解：这些公司未计入我们报告的31亿美元利润，对我们而言与伯克希尔记录的部分同样有价值。</p><p>这些被投资方保留的利润常用于回购自身股票——这一举措在不需我们花一分钱的情况下提升了伯克希尔在未来利润中的份额。其保留利润也为商业机会提供资金，这些机会通常证明是有利的。所有这些都使我们有理由预期，这四家被投资方的每股利润合计将随时间大幅增长（尽管2015年对集团将是艰难的一年，部分原因是美元走强）。如果预期收益实现，伯克希尔的股息将增加，更重要的是，我们的未实现资本收益也将增加。（对这四家公司合计，我们年末未实现收益已达420亿美元。）</p><p>我们在资本配置上的灵活性——愿意将大笔资金被动投资于非控股企业——赋予我们显著优势，超越那些仅限于收购可运营企业的公司。我们对运营企业或被动投资的胃口翻倍了我们为伯克希尔源源不断的现金找到合理用途的机会。</p><p><strong>• 我过去曾提到，我的商业经验有助于我作为投资者，而我的投资经验使我成为更好的商人。两种追求相互传授适用的教训。有些真理只能通过经验完全学到。（在弗雷德·施韦德精彩的《客户的游艇在哪里？》一书中，一幅彼得·阿诺的漫画描绘了一个困惑的亚当看着热切的夏娃，配文说：&quot;有些事情无法用言语或图片向处女充分解释。&quot;如果你还没读过施韦德的书，请在我们年会上买一本。其智慧和幽默真正无价。）</strong></p><p>在阿诺所说的&quot;某些事情&quot;中，我会包括两项独立的技能：投资评估和企业管理。因此，我认为让我们的两位投资经理托德·库姆斯和泰德·韦斯勒各自监管至少一家我们的企业是值得的。几个月前，当我们同意收购两家公司时，一个合理的机会出现了——虽然规模小于我们通常收购的企业，但具有出色的经济特征。两家合计每年盈利约1亿美元，净资产约1.25亿美元。</p><p>我请托德和泰德各自担任一家公司的董事长，在这个职位上，他们将以非常有限的方式运作，就像我对我们较大子公司所做的那样。这种安排将为我节省少量工作，更重要的是，使他们两人成为比现在更优秀的投资者（也就是说，他们已跻身最优秀之列）。</p><hr><p>2009年末，在大衰退的阴霾中，我们同意收购BNSF——伯克希尔历史上最大的一笔收购。当时，我称这笔交易为&quot;对美国经济未来的全押注&quot;。</p><p>这种承诺对我们来说并不新鲜。自巴菲特合伙有限公司1965年取得伯克希尔控股权以来，我们一直在进行类似的押注。这也是有充分理由的：查理和我一直认为，押注美国不断增长的繁荣是非常接近确定的事。</p><p>事实上，在过去238年里，谁曾因做空美国而获益？如果你将我国目前的状况与1776年相比，你会惊叹不已。仅在我有生之年，美国实际人均产出就增长了六倍。我的父母在1930年无法想象他们的儿子将看到的世界。尽管悲观主义的传教士喋喋不休地谈论美国的问题，但我从未见过有人希望移民（虽然我可以想到几位，我很乐意为他们买单程机票）。</p><p>嵌入我们市场经济中的活力将继续施展其魔力。收益不会以平滑或连续的方式到来——从未如此。我们将定期抱怨我们的政府。但最肯定的是，美国最好的日子还在前面。</p><p>在这一顺风推动下，查理和我希望通过以下方式建立伯克希尔的每股内在价值：（1）持续改善我们众多子公司的基本盈利能力；（2）通过补强收购进一步提高其利润；（3）受益于我们被投资方的增长；（4）当伯克希尔股票以显著低于内在价值的折扣交易时回购股票；（5）偶尔进行大型收购。我们还将通过极少发行伯克希尔股票来为您最大化收益。</p><p>这些建筑模块建立在坚如磐石的基础上。一个世纪后，BNSF和伯克希尔哈撒韦能源仍将在我们的经济中发挥重要作用。住房和汽车仍将是大多数家庭生活的核心。保险对企业和个人仍将至关重要。展望未来，查理和我看到一个为伯克希尔量身定做的世界。我们很幸运被托付其管理工作。</p><hr><h2 id="内在商业价值" tabindex="-1">内在商业价值 <a class="header-anchor" href="#内在商业价值" aria-label="Permalink to &quot;内在商业价值&quot;">​</a></h2><p>尽管查理和我经常谈论内在商业价值，但我们无法告诉您伯克希尔股票（事实上，任何其他股票）该数字的确切值。然而，在我们2010年年度报告中，我们列出了三个要素——其中一个是定性的——我们相信它们是合理估算伯克希尔内在价值的关键。该讨论全文转载于第123-124页。</p><p>以下是两个定量因素的更新：2014年我们的每股投资增长8.4%至140,123美元，我们的非保险和非投资业务利润增长19%至每股10,847美元。</p><p>自1970年以来，我们的每股投资以19%的年复合增长率增长，我们的利润数字以20.6%的年率增长。这并非巧合：在随后的44年里，伯克希尔股票价格的上涨速度与我们的两个价值衡量指标非常相似。查理和我乐于看到两个领域的增长，但我们的主要重点是建立运营利润。这就是为什么我们去年很高兴用我们的菲利普66和格雷厄姆控股公司股票交换运营业务，并与宝洁公司签约以类似交换方式收购金霸王，该交易将于2015年完成。</p><hr><p>现在，让我们审视我们运营的四个主要板块。每个板块的资产负债表和收入特征与其他板块截然不同。因此，我们将它们作为四个独立的业务呈现，这也是查理和我看待它们的方式（尽管将它们全部置于一个屋檐下有重要且持久的优势）。我们的目标是向您提供如果我们的位置互换——您作为报告经理，我们作为缺席股东——我们希望获得的信息。（但别动歪脑筋！）</p><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><p>让我们首先看保险，伯克希尔的核心业务。自1967年我们以860万美元收购国民赔偿公司及其姊妹公司国民火灾与海上保险公司以来，该行业一直是推动我们扩张的引擎。尽管那次收购对伯克希尔产生了深远影响，但其执行却极其简单。</p><p>我的朋友杰克·林沃特是这两家公司的控股股东，他来到我的办公室说他想出售。十五分钟后，我们达成协议。杰克的公司从未经公共会计师事务所审计，我也没要求审计。我的理由是：（1）杰克诚实；（2）他也有点古怪，如果交易变得复杂，他很可能会走开。</p><p>第128-129页转载了我们用于完成交易的1½页购买协议。那份合同是自制的：双方都未使用律师。按每页计算，这必定是伯克希尔最划算的交易：国民赔偿公司如今GAAP（公认会计原则）净资产达1,110亿美元，超过世界上任何其他保险公司。</p><p>我们被财产意外险业务吸引的一个原因是其财务特征：P/C保险人预先收取保费，日后支付索赔。在极端情况下，如某些工伤事故，赔付可能延续数十年。这种先收后付模式使P/C公司持有大量资金——我们称之为&quot;浮存金&quot;——最终将支付给他人。同时，保险人可以将这笔浮存金投资以获取收益。虽然个别保单和索赔来来去去，但保险人持有的浮存金金额通常与保费量保持相当稳定的关系。因此，随着业务增长，我们的浮存金也在增长。我们的增长情况如下表所示：</p><table tabindex="0"><thead><tr><th>年份</th><th>浮存金（百万美元）</th></tr></thead><tbody><tr><td>1970</td><td>39</td></tr><tr><td>1980</td><td>237</td></tr><tr><td>1990</td><td>1,632</td></tr><tr><td>2000</td><td>27,871</td></tr><tr><td>2010</td><td>65,832</td></tr><tr><td>2014</td><td>83,921</td></tr></tbody></table><p>浮存金的进一步增长将难以实现。好的一面是，GEICO和我们新的商业保险业务几乎肯定会以良好速度增长。然而，国民赔偿公司的再保险部门是若干清盘合约的一方，其浮存金逐渐下降。如果我们确实经历浮存金下降，那将非常缓慢——最多每年不超过3%。我们保险合约的性质决定了我们永远不会面临与现金资源相比数额巨大的即时支付要求。这一实力是伯克希尔经济堡垒的关键支柱。</p><p>如果我们的保费超过费用和最终损失的总和，我们就会记录承保利润，这增加了我们的浮存金产生的投资收益。当获得这种利润时，我们享受免费资金的使用——更好的是，我们还因持有它而获得报酬。</p><p>不幸的是，所有保险人实现这一美好结果的愿望造成了激烈的竞争，如此激烈以至于经常导致整个P/C行业在承保上出现重大亏损。这种亏损实际上是行业为持有其浮存金所支付的代价。竞争态势几乎保证了保险业——尽管其所有公司都享有浮存金收益——将继续其相对于其他美国企业在有形净资产上获得低于正常回报的惨淡记录。我国目前经历的长期低利率时期导致浮存金收益下降，从而加剧了行业的利润问题。</p><p>如本报告第一部分所述，伯克希尔现已连续12年实现承保盈利，该期间税前收益总计240亿美元。展望未来，我相信我们在大多数年份将继续承保盈利。这是我们所有保险经理每日关注的焦点，他们知道虽然浮存金有价值，但其好处可能被糟糕的承保结果淹没。这一信息至少得到所有保险人的口头认可；在伯克希尔，它是一种信仰。</p><p>那么我们的浮存金如何影响内在价值？当计算伯克希尔的账面价值时，我们浮存金的全部金额作为负债扣除，就像我们明天必须支付且无法补充一样。但将浮存金严格视为负债是错误的；它应被视为一种周转资金。每日，我们支付旧索赔和相关费用——2014年向超过600万索赔人支付了227亿美元的巨额款项——这减少了浮存金。同样确定的是，我们每天承保新业务，从而产生增加浮存金的新索赔。</p><p>如果我们的周转浮存金既无成本又长期持续——我相信它将是——那么这一负债的真实价值就远低于会计负债。欠下实际上永远不会离开场所的1美元——因为新业务几乎肯定会带来替代——与欠下明天将出门且不会被替换的1美元有天壤之别。然而，在GAAP下，这两种类型的负债被视为相等。</p><p>对这一夸大的负债的部分抵消是我们购买保险公司时产生的155亿美元&quot;商誉&quot;资产，这增加了账面价值。在很大程度上，这笔商誉代表我们为保险业务的浮存金生成能力支付的价格。然而，商誉的成本与其真实价值无关。例如，如果一家保险公司遭受重大且长期的承保亏损，账面上携带的任何商誉资产都应被视为毫无价值，无论其原始成本如何。</p><p>幸运的是，这并不描述伯克希尔。查理和我相信，我们保险商誉的真实经济价值——如果我们购买具有类似质量浮存金的保险业务，我们会乐于支付的价格——远超其历史账面价值。根据现行会计准则（我们同意），这一超额价值永远不会计入我们的账簿。但我可以向您保证，它是真实的。这是原因之一——一个巨大原因——为什么我们相信伯克希尔的内在商业价值大大超过其账面价值。</p><hr><p>伯克希尔有吸引力的保险经济之所以存在，仅因为我们有一些出色的经理人在运营纪律严明、商业模式难以复制的业务。让我告诉您主要单位的情况。</p><p>按浮存金规模首先是伯克希尔哈撒韦再保险集团，由阿吉特·贾恩管理。阿吉特承保其他人没有意愿或资本承担的风险。他的运营结合了能力、速度、果断，以及最重要的智慧，在保险业中独一无二。但他从未使伯克希尔面临与我们的资源相比不适当的风险。</p><p>事实上，我们在规避风险方面比大多数大型保险公司更为保守。例如，如果保险业遭受某场超级灾难带来的2,500亿美元损失——约为其经历过任何损失的三倍——伯克希尔整体很可能仍会记录可观的年度利润，因为其众多利润流。我们仍将现金充裕，并会在可能已陷入休克的市场中寻找大机会。同时，其他主要保险公司和再保险公司将深陷赤字，甚至面临资不抵债。</p><p>阿吉特的承保技能无与伦比。此外，他的头脑是一个创意工厂，总是寻找可以添加到现有组合中的更多业务线。去年我告诉您他创建了伯克希尔哈撒韦专业保险公司（&quot;BHSI&quot;）。这一举措使我们进入商业保险领域，立即受到美国各地主要保险经纪人和企业风险管理人的欢迎。此前，我们仅承保少数专门的商业保险线。</p><p>BHSI由彼得·伊斯特伍德领导，他是一位在保险界广受尊敬的经验丰富的承保人。2014年期间，彼得扩充了他的人才团队，进入了国际业务和新的保险线。我们重申去年的预测：BHSI将成为伯克希尔的重要资产，几年内将产生数十亿美元的业务量。</p><hr><p>我们在通用再保险公司还有另一个再保险巨头，由塔德·蒙特罗斯管理。</p><p>归根结底，稳健的保险运营需要遵守四项纪律。它必须：（1）了解所有可能导致保单发生损失的敞口；（2）保守评估任何敞口实际造成损失的可能性以及如果发生时的可能成本；（3）设定平均而言在覆盖预期损失成本和运营费用后能带来利润的保费；（4）如果无法获得适当保费，愿意放弃业务。</p><p>许多保险人通过了前三项测试，却在第四项上失败。他们简直无法背弃竞争对手正在踊跃承保的业务。那句老话&quot;别人都在做，所以我们也必须做&quot;，在任何业务中都意味着麻烦，但在保险业尤为如此。</p><p>塔德遵守了所有四条保险诫命，这体现在他的业绩上。在他的领导下，通用再保险的巨额浮存金远非免费，而且我们预期平均而言这种情况将继续。我们对通用再保险的国际人寿再保险业务尤为热衷，自1998年收购该公司以来，该业务持续盈利增长。</p><p>值得铭记的是，我们收购通用再保险后不久，它就陷入问题，导致评论者——以及我本人，短暂地——认为我犯了一个巨大错误。那一天早已过去。通用再保险现在是一颗宝石。</p><hr><p>最后是GEICO，我64年前初试保险锋芒的公司。GEICO由托尼·奈斯利管理，他18岁加入公司，2014年完成53年服务。托尼1993年成为CEO，此后公司一直在腾飞。没有比托尼更好的经理人了。</p><p>1951年1月我第一次接触GEICO时，我被该公司相对于行业巨头所承受费用的巨大成本优势所震撼。我清楚地看到GEICO会成功，因为它值得成功。没人喜欢购买汽车保险。然而，几乎每个人都喜欢开车。因此所需的保险是大多数家庭的一项主要支出。节省对他们很重要——只有低成本运营才能提供这些节省。事实上，阅读这封信的人中至少有40%可以通过向GEICO投保来省钱。所以停止阅读，访问geico.com或致电800-368-2730。</p><p>GEICO的成本优势是该公司年复一年蚕食市场份额的因素。（我们2014年末市场份额为10.8%，而1995年伯克希尔取得GEICO控制权时为2.5%。）公司的低成本创造了一条护城河——一条持久的护城河——竞争对手无法跨越。我们的壁虎从不厌倦告诉美国人GEICO可以为他们节省重要资金。我应该补充，壁虎有一个特别讨人喜欢的品质——他无偿工作。与人类代言人不同，他从未因名气而自我膨胀，也没有经纪人不断提醒我们他多么有价值。我爱这个小家伙。</p><hr><p>除了三大保险运营外，我们拥有一组较小的公司，其中大多数在保险世界的奇角从事业务。总体而言，这些公司是一个不断增长的业务，持续实现承保盈利。事实上，在过去十年中，它们承保盈利29.5亿美元，同时浮存金从17亿美元增长到86亿美元。查理和我珍视这些公司及其经理人。</p><p><strong>承保利润与年末浮存金（百万美元）</strong></p><table tabindex="0"><thead><tr><th>保险业务</th><th>2014年利润</th><th>2013年利润</th><th>2014年浮存金</th><th>2013年浮存金</th></tr></thead><tbody><tr><td>BH再保险</td><td>606</td><td>1,294</td><td>42,454</td><td>37,231</td></tr><tr><td>通用再保险</td><td>277</td><td>283</td><td>19,280</td><td>20,013</td></tr><tr><td>GEICO</td><td>1,159</td><td>1,127</td><td>13,569</td><td>12,566</td></tr><tr><td>其他主要业务</td><td>626</td><td>385</td><td>8,618</td><td>7,430</td></tr><tr><td><strong>合计</strong></td><td><strong>2,668</strong></td><td><strong>3,089</strong></td><td><strong>83,921</strong></td><td><strong>77,240</strong></td></tr></tbody></table><hr><p>简而言之，保险是承诺的销售。&quot;客户&quot;现在支付金钱；保险人承诺如果某些不希望的事件发生，将来支付金钱。</p><p>有时，承诺在几十年内不会被检验。（想想20多岁的人购买人寿保险。）因此，保险人支付的能力和意愿——即使付款时刻到来时经济混乱盛行——是最重要的。</p><p>伯克希尔的承诺无与伦比，近年来世界上一些最大和最复杂的P/C保险人肯定了这一事实，他们希望摆脱巨大且异常长久的负债。也就是说，这些保险人希望将这些负债&quot;分出&quot;——其中大部分是石棉索赔的潜在损失——给再保险人。但他们需要合适的人选：如果再保险人未能支付损失，原保险人仍需承担。因此，选择一个日后证明资金紧张或行为不端的再保险人，威胁原保险人将巨额负债重新揽回。</p><p>去年，我们再保险领域的领先地位得到确认，我们承保了一份收取30亿美元单一保费的保单。我相信该保单的规模仅被我们2007年与劳合社的交易超越，当时保费为71亿美元。</p><p>事实上，我知道历史上仅有八份P/C保单的单一保费超过10亿美元。而且，是的，这八份都由伯克希尔承保。其中某些合约将要求我们在50年或更长时间后支付大量款项。当主要保险人需要一个关于此类支付将作出的无可置疑的承诺时，伯克希尔是被呼叫的一方——唯一的一方。</p><hr><p>伯克希尔的杰出经理人、卓越财务实力和受宽阔护城河保护的各种商业模式，在保险世界中构成了独特的东西。这种力量集合对伯克希尔股东而言是一笔巨大资产，只会随时间变得更有价值。</p><hr><h2 id="受监管的资本密集型业务" tabindex="-1">受监管的资本密集型业务 <a class="header-anchor" href="#受监管的资本密集型业务" aria-label="Permalink to &quot;受监管的资本密集型业务&quot;">​</a></h2><p>我们有两个主要运营——BNSF和伯克希尔哈撒韦能源公司（&quot;BHE&quot;）——它们具有区别于我们其他业务的重要共同特征。因此，我们在本信中为它们单独设立一节，并在我们的GAAP资产负债表和损益表中单独列出其合并财务统计数据。</p><p>两家公司的一个关键特征是它们对非常长久的受监管资产进行巨额投资，这些投资部分由大量非伯克希尔担保的长期债务融资。我们的信用实际上并不需要，因为每家公司都具有即使在糟糕的经济条件下也将远超其利息要求的盈利能力。例如，去年BNSF的利息覆盖倍数超过8:1。（我们将覆盖定义为税前利润/利息，而非EBITDA/利息，后者是我们视为严重缺陷的常用衡量标准。）在BHE，同时有两个因素确保公司在所有情况下偿付债务的能力。第一个是所有公用事业公司共有的：抗衰退收益，因为这些公司以独家方式提供基本服务。第二个是少数其他公用事业公司享有的：利润流的巨大多样性，这保护我们免受任何单一监管机构的严重伤害。最近，我们通过30亿加元收购AltaLink进一步拓宽了这一基础——这是一个服务阿尔伯塔省85%人口的输电系统。这种利润流的多样性，加上由强大母公司拥有的固有优势，使BHE及其公用事业子公司能够显著降低其债务成本。这一经济事实既有利于我们也有利于我们的客户。</p><p>每天，我们的两家子公司以重要方式为美国经济提供动力：</p><p>• BNSF承运约15%（以吨英里计）的所有城际货运，无论通过卡车、铁路、水路、航空还是管道运输。事实上，我们运输的货物吨英里数超过任何其他人，这一事实确立了BNSF是我们经济循环系统中最重要的大动脉。</p><p>BNSF像所有铁路一样，也以极其节省燃料和环境友好的方式运输货物，用一加仑柴油将一吨货物运输约500英里。承担同样工作的卡车消耗约四倍的燃料。</p><p>• BHE的公用事业公司服务于11个州的受监管零售客户。没有公用事业公司延伸更远。此外，我们是可再生能源领域的领导者：从十年前的零起点开始，BHE现在占全国风力发电能力的6%和太阳能发电能力的7%。除了这些业务，BHE拥有两条输送我国8%天然气消费的管道；最近在加拿大购买的输电业务；以及在英国和菲律宾的主要电力业务。节拍继续：我们将在未来几十年继续在世界各地购买和建设公用事业运营。</p><p>BHE能够进行这些投资是因为它保留所有利润。事实上，去年该公司保留的利润美元金额——远超——任何其他美国电力公用事业公司。我们和我们的监管者将这一100%留存政策视为重要优势——这一优势几乎肯定将在未来多年使BHE区别于其他公用事业公司。</p><p>当BHE完成正在进行中的某些可再生能源项目时，该公司的可再生能源组合将耗资150亿美元。此外，我们有在建的常规项目，也将耗资数十亿。我们乐于做出此类承诺，只要它们承诺合理回报——在这方面，我们对未来监管给予很大信任。</p><p>我们的信心既来自过去的经验，也来自社会永远需要在交通和能源方面进行大量投资这一认知。以善待资本提供者的方式对待他们，确保基本项目的资金持续流动，这符合政府的自身利益。同时，以赢得监管者和其所代表人民认可的方式开展运营，也符合我们的自身利益。</p><p>去年我们在BHE完全实现了这一目标，正如我们拥有期间的每一年一样。我们的费率保持低廉，客户满意度高，员工安全记录在行业中名列前茅。</p><p>然而，BNSF的情况——如我之前所述——在2014年并不好，这一年铁路公司让许多客户失望。尽管BNSF近年来进行了创纪录的资本支出，远超主要竞争对手联合太平洋铁路的支出，问题仍然发生。</p><p>按收入衡量，两家铁路公司规模大致相当，尽管我们运输更多货物（以车皮或吨英里计）。但去年我们的服务问题超过联合太平洋，我们因此失去市场份额。此外，联合太平洋的利润超过我们创纪录的金额。显然，我们有很多工作要做。</p><p>我们没有浪费时间：如我之前所述，我们将在2015年投入60亿美元改善铁路运营。这将约占预计收入的26%（这一计算是行业的衡量标准）。如此规模的支出在铁路公司中几乎闻所未闻。对我们而言，这一比例与我们2009-2013年18%的平均水平相比，以及联合太平洋近期16-17%的预测相比。我们的巨额投资将很快带来更大容量和更好服务的系统。利润改善应随之而来。</p><p>以下是伯克希尔哈撒韦能源和BNSF的关键数据：</p><p><strong>伯克希尔哈撒韦能源（持股89.9%）利润（百万美元）</strong></p><table tabindex="0"><thead><tr><th>业务</th><th>2014</th><th>2013</th><th>2012</th></tr></thead><tbody><tr><td>英国公用事业</td><td>527</td><td>362</td><td>429</td></tr><tr><td>爱荷华公用事业</td><td>298</td><td>230</td><td>236</td></tr><tr><td>内华达公用事业</td><td>549</td><td>—</td><td>—</td></tr><tr><td>PacifiCorp（主要俄勒冈和犹他）</td><td>1,010</td><td>982</td><td>737</td></tr><tr><td>天然气管道（Northern Natural和Kern River）</td><td>379</td><td>385</td><td>383</td></tr><tr><td>HomeServices</td><td>139</td><td>139</td><td>82</td></tr><tr><td>其他（净额）</td><td>236</td><td>4</td><td>91</td></tr><tr><td><strong>运营利润（扣除公司利息和税前）</strong></td><td><strong>3,138</strong></td><td><strong>2,102</strong></td><td><strong>1,958</strong></td></tr><tr><td>利息</td><td>427</td><td>296</td><td>314</td></tr><tr><td>所得税</td><td>616</td><td>170</td><td>172</td></tr><tr><td><strong>净利润</strong></td><td><strong>2,095</strong></td><td><strong>1,636</strong></td><td><strong>1,472</strong></td></tr><tr><td><strong>伯克希尔应占利润</strong></td><td><strong>1,882</strong></td><td><strong>1,470</strong></td><td><strong>1,323</strong></td></tr></tbody></table><p><strong>BNSF利润（百万美元）</strong></p><table tabindex="0"><thead><tr><th>项目</th><th>2014</th><th>2013</th><th>2012</th></tr></thead><tbody><tr><td>收入</td><td>23,239</td><td>22,014</td><td>20,835</td></tr><tr><td>运营费用</td><td>16,237</td><td>15,357</td><td>14,835</td></tr><tr><td><strong>运营利润（利息和税前）</strong></td><td><strong>7,002</strong></td><td><strong>6,657</strong></td><td><strong>6,000</strong></td></tr><tr><td>利息（净额）</td><td>833</td><td>729</td><td>623</td></tr><tr><td>所得税</td><td>2,300</td><td>2,135</td><td>2,005</td></tr><tr><td><strong>净利润</strong></td><td><strong>3,869</strong></td><td><strong>3,793</strong></td><td><strong>3,372</strong></td></tr></tbody></table><hr><h2 id="制造、服务和零售业务" tabindex="-1">制造、服务和零售业务 <a class="header-anchor" href="#制造、服务和零售业务" aria-label="Permalink to &quot;制造、服务和零售业务&quot;">​</a></h2><p>我们在伯克希尔这一部分的活动包罗万象。不过，让我们看看整个集团的汇总资产负债表和损益表。</p><p><strong>资产负债表 2014年12月31日（百万美元）</strong></p><table tabindex="0"><thead><tr><th>资产</th><th></th><th>负债和权益</th><th></th></tr></thead><tbody><tr><td>现金及等价物</td><td>5,765</td><td>应付票据</td><td>965</td></tr><tr><td>应收账款和票据</td><td>8,264</td><td>其他流动负债</td><td>9,734</td></tr><tr><td>存货</td><td>10,236</td><td><strong>流动负债合计</strong></td><td><strong>10,699</strong></td></tr><tr><td>其他流动资产</td><td>1,117</td><td></td><td></td></tr><tr><td><strong>流动资产合计</strong></td><td><strong>25,382</strong></td><td>递延税款</td><td>3,801</td></tr><tr><td></td><td></td><td>商誉和其他无形资产</td><td>28,107</td></tr><tr><td>固定资产</td><td>13,806</td><td>长期债务和其他负债</td><td>4,269</td></tr><tr><td>其他资产</td><td>3,793</td><td>少数股东权益</td><td>492</td></tr><tr><td></td><td></td><td>伯克希尔权益</td><td>51,827</td></tr><tr><td><strong>合计</strong></td><td><strong>71,088</strong></td><td><strong>合计</strong></td><td><strong>71,088</strong></td></tr></tbody></table><p><strong>损益表（百万美元）</strong></p><table tabindex="0"><thead><tr><th>项目</th><th>2014</th><th>2013*</th><th>2012*</th></tr></thead><tbody><tr><td>收入</td><td>97,689</td><td>93,472</td><td>81,432</td></tr><tr><td>运营费用</td><td>90,788</td><td>87,208</td><td>75,734</td></tr><tr><td>利息费用</td><td>109</td><td>104</td><td>112</td></tr><tr><td><strong>税前利润</strong></td><td><strong>6,792</strong></td><td><strong>6,160</strong></td><td><strong>5,586</strong></td></tr><tr><td>所得税和少数股东权益</td><td>2,324</td><td>2,283</td><td>2,229</td></tr><tr><td><strong>净利润</strong></td><td><strong>4,468</strong></td><td><strong>3,877</strong></td><td><strong>3,357</strong></td></tr></tbody></table><p>*2012年和2013年利润已重述，排除Marmon的租赁业务，该业务现已列入金融和金融产品部分。</p><p>我们符合GAAP的收入和费用数据见第49页。相比之下，上述运营费用数字是非GAAP的，排除了一些购买会计项目（主要是某些无形资产的摊销）。我们以这种方式呈现数据，是因为查理和我相信，调整后的数字比GAAP数字更准确地反映表中汇总企业的真实经济费用和利润。</p><p>我不会解释所有调整——有些很小且晦涩——但认真的投资者应该理解无形资产的不同性质。有些确实随时间消耗，而另一些则绝不损失价值。以软件为例，摊销费用是非常真实的费用。然而，对其他无形资产（如客户关系摊销）进行摊销的概念源于购买会计规则，显然不反映现实。GAAP会计不区分这两种费用。两者在计算利润时都记录为费用——尽管从投资者角度看，它们可能天差地别。</p><p>在第49页我们展示的符合GAAP的数字中，已扣除11.5亿美元的摊销费用。我们会称其中约20%为&quot;真实&quot;费用，其余则不是。这些&quot;非真实&quot;费用在伯克希尔曾经不存在，但因为我们进行了许多收购而变得重大。随着我们收购更多公司，非真实摊销费用几乎肯定会进一步增加。</p><p>第67页符合GAAP的表格向您展示我们无形资产的当前状况。我们现在还有74亿美元待摊销，其中41亿美元将在未来五年内计提。当然，最终，每一美元非真实费用都将完全计提完毕。当这发生时，报告利润将增加，即使真实利润持平。</p><p>我们要强调，折旧费用不同：我们报告的每一分钱折旧费用都是真实成本。这对大多数其他公司也是如此。当CEO吹捧EBITDA作为估值指南时，给他们接上测谎仪。</p><p>我们公开的利润报告当然将继续符合GAAP。然而，要拥抱现实，您应该记得加回我们报告的大部分摊销费用。</p><hr><p>回到我们众多的制造、服务和零售运营，它们销售从棒棒糖到喷气式飞机等各种产品。该板块的一些企业，以无杠杆有形净资产收益率衡量，享有惊人的经济效益，税后利润从25%到远超100%。另一些产生12%至20%的良好回报。然而，少数回报很差，这是我在资本配置工作中犯下一些严重错误的结果。我没有被误导；我只是对公司或其所在行业的经济动态评估错误。</p><p>幸运的是，我的失误通常涉及相对较小的收购。我们的大型收购总体运作良好，有些甚至非常好。不过，我还没有在购买企业或股票上犯下最后一个错误。并非一切都按计划进行。</p><p>作为一个单一实体来看，该集团的公司是优秀业务。2014年它们平均使用240亿美元有形净资产，尽管持有大量超额现金且杠杆很少，税后资本回报率达18.7%。</p><p>当然，如果以过高价格购买，具有惊人经济效益的企业也可能是糟糕投资。我们为大多数企业支付了相对于有形净资产的大幅溢价，这一成本反映在我们为商誉列示的大额数字上。不过总体而言，我们在该板块部署的资本获得了不错的回报。此外，这些企业的内在价值合计超过其账面价值相当幅度，这一溢价可能会扩大。即便如此，保险和受监管行业板块的内在价值与账面价值差距要大得多。那里才是真正大赢家所在。</p><hr><p>我们在该集团有太多公司，无法逐一评论。此外，其竞争对手——现有和潜在的——都在阅读本报告。在我们某些业务中，如果他人知道我们的数字，我们可能会处于劣势。因此，对于我们某些规模不足以影响伯克希尔评估的运营，我们只披露必要信息。不过，您可以在第97-100页找到关于我们许多运营的大量细节。</p><hr><h2 id="金融和金融产品" tabindex="-1">金融和金融产品 <a class="header-anchor" href="#金融和金融产品" aria-label="Permalink to &quot;金融和金融产品&quot;">​</a></h2><p>今年我们将Marmon规模可观的租赁业务列入本部分，其产品包括铁路车辆、集装箱和起重机。我们也重述了前两年以反映这一变化。为什么我们这样做？曾几何时，Marmon存在大量少数股权，我认为将公司所有运营放在一处更易理解。如今我们拥有Marmon几乎100%股权，这使我认为将Marmon的租赁业务列入本标题下会让您更深入了解我们的各项业务。（Marmon其他数十项业务的数字仍在前一部分。）</p><p>我们的其他租赁和租赁业务由CORT（家具）和XTRA（半挂车）进行。这些公司是行业领导者，随着美国经济走强，其利润大幅增长。两家公司在新设备上的投资超过许多竞争对手，这正在获得回报。</p><p>凯文·克莱顿再次在克莱顿家园——美国最大的住宅建造商——交出行业领先的业绩。去年，克莱顿售出30,871套住宅，约占美国人购买的预制住宅的45%。2003年我们以17亿美元收购克莱顿时，其份额为14%。</p><p>克莱顿利润的关键是公司130亿美元的抵押贷款组合。在2008和2009年金融恐慌期间，当行业资金枯竭时，克莱顿能够继续放贷，因为伯克希尔的支持。事实上，我们在该期间继续为我们竞争对手的零售销售以及我们自己的销售提供融资。</p><p>克莱顿的许多借款人收入较低，FICO评分平庸。但得益于公司审慎的放贷做法，其组合在衰退期间表现良好，意味着我们很大比例的借款人保住了他们的房屋。我们的蓝领借款人在许多情况下证明是比其高收入同胞更好的信用风险。</p><p>在Marmon的铁路车辆业务，租赁费率过去几年大幅提高。然而，该业务的性质是每年只有约20%的租赁到期。因此，提高的价格只能逐渐进入我们的收入流。不过，趋势强劲。我们105,000辆车的车队主要由罐车组成，但其中仅8%运输原油。</p><p>关于我们铁路业务的另一个事实对您很重要：与许多其他出租方不同，我们制造自己的罐车，好年份约6,000辆。我们将车辆从制造部门转移到租赁部门时不计入任何利润。因此，我们的车队以&quot;便宜&quot;价格入账。该数字与&quot;零售&quot;价格的差异只能通过我们在车辆30年寿命内享受的较小年度折旧费用缓慢反映在我们的利润中。由于这一事实及其他因素，Marmon的铁路车队价值远高于账面上的50亿美元。</p><p>以下是该板块利润汇总：</p><p><strong>金融和金融产品利润（百万美元）</strong></p><table tabindex="0"><thead><tr><th>业务</th><th>2014</th><th>2013</th><th>2012</th></tr></thead><tbody><tr><td>Berkadia（我们50%份额）</td><td>122</td><td>80</td><td>35</td></tr><tr><td>克莱顿</td><td>558</td><td>416</td><td>255</td></tr><tr><td>CORT</td><td>36</td><td>40</td><td>42</td></tr><tr><td>Marmon——集装箱和起重机</td><td>238</td><td>226</td><td>246</td></tr><tr><td>Marmon——铁路车辆</td><td>442</td><td>353</td><td>299</td></tr><tr><td>XTRA</td><td>147</td><td>125</td><td>106</td></tr><tr><td>净金融收入*</td><td>296</td><td>324</td><td>410</td></tr><tr><td><strong>合计</strong></td><td><strong>1,839</strong></td><td><strong>1,564</strong></td><td><strong>1,393</strong></td></tr></tbody></table><p>*排除资本损益</p><hr><h2 id="投资" tabindex="-1">投资 <a class="header-anchor" href="#投资" aria-label="Permalink to &quot;投资&quot;">​</a></h2><p>以下列出我们年末市值最大的十五项普通股投资：</p><p><strong>2014年12月31日</strong></p><table tabindex="0"><thead><tr><th>持股数（百万）</th><th>公司</th><th>持股比例</th><th>成本*</th><th>市值</th></tr></thead><tbody><tr><td>151,610,700</td><td>美国运通公司</td><td>14.8%</td><td>1,287</td><td>14,106</td></tr><tr><td>400,000,000</td><td>可口可乐公司</td><td>9.2%</td><td>1,299</td><td>16,888</td></tr><tr><td>18,513,482</td><td>DaVita医疗合伙人公司</td><td>8.6%</td><td>843</td><td>1,402</td></tr><tr><td>15,430,586</td><td>迪尔公司</td><td>4.5%</td><td>1,253</td><td>1,365</td></tr><tr><td>24,617,939</td><td>直播电视公司</td><td>4.9%</td><td>1,454</td><td>2,134</td></tr><tr><td>13,062,594</td><td>高盛集团</td><td>3.0%</td><td>750</td><td>2,532</td></tr><tr><td>76,971,817</td><td>国际商业机器公司</td><td>7.8%</td><td>13,157</td><td>12,349</td></tr><tr><td>24,669,778</td><td>穆迪公司</td><td>12.1%</td><td>248</td><td>2,364</td></tr><tr><td>20,060,390</td><td>慕尼黑再保险</td><td>11.8%</td><td>2,990</td><td>4,023</td></tr><tr><td>52,477,678</td><td>宝洁公司</td><td>1.9%</td><td>336</td><td>4,683***</td></tr><tr><td>22,169,930</td><td>赛诺菲</td><td>1.7%</td><td>1,721</td><td>2,032</td></tr><tr><td>96,890,665</td><td>美国合众银行</td><td>5.4%</td><td>3,033</td><td>4,355</td></tr><tr><td>43,387,980</td><td>USG公司</td><td>30.0%</td><td>836</td><td>1,214</td></tr><tr><td>67,707,544</td><td>沃尔玛百货公司</td><td>2.1%</td><td>3,798</td><td>5,815</td></tr><tr><td>483,470,853</td><td>富国银行公司</td><td>9.4%</td><td>11,871</td><td>26,504</td></tr><tr><td>其他</td><td></td><td></td><td>10,180</td><td>15,704</td></tr><tr><td><strong>按市值计的普通股合计</strong></td><td></td><td></td><td><strong>55,056</strong></td><td><strong>117,470</strong></td></tr></tbody></table><p>*这是我们的实际购买价格，也是我们的税基；GAAP&quot;成本&quot;在少数情况下因GAAP规则要求的增减值而不同。 **排除伯克希尔子公司养老基金持有的股份。 ***按合同以该金额出售。</p><p>伯克希尔有一项主要股权头寸未列入上表：我们可在2021年9月之前的任何时间以50亿美元购买美国银行7亿股股票。年末这些股票价值125亿美元。我们很可能在期权到期前购买这些股票。同时，重要的是您要认识到，美国银行实际上是我们第四大股权投资——而且我们给予高度评价。</p><hr><p>细心的读者会注意到，Tesco去年出现在我们最大普通股投资名单中，现在却不见了。一个细心的投资者——我很尴尬地报告——应该更早卖出Tesco股票。我在这项投资上犯了大错，因为犹豫不决。</p><p>2012年末，我们持有4.15亿股Tesco股票，该公司当时和现在都是英国领先的食品零售商，在其他国家也是重要的杂货商。我们这项投资的成本为23亿美元，市值也类似。</p><p>2013年，我对该公司当时的管理层有些不满，出售了1.14亿股，实现利润4,300万美元。我从容的卖出速度将被证明代价高昂。查理称这种行为为&quot;吮拇指&quot;。（考虑到我的延误让我们付出的代价，他是在客气。）</p><p>2014年期间，Tesco的问题逐月恶化。公司市场份额下降，利润率收缩，会计问题浮出水面。在商业世界，坏消息往往接连出现：你在厨房看到一只蟑螂；随着日子过去，你会遇到它的亲戚。</p><p>我们在全年卖出Tesco股票，现已清仓。（应该提到，公司已聘请新管理层，我们祝愿他们顺利。）我们这项投资的税后亏损为4.44亿美元，约为伯克希尔净资产的五分之一个百分点。在过去50年里，我们仅有一次实现的投资亏损在当时使我们损失了净资产的2%。有两次经历了1%的亏损。这三次亏损都发生在1974-1975年期间，当时我们卖出很便宜的股票以购买我们认为更便宜的股票。</p><hr><p>我们的投资结果得益于强劲的顺风。在1964-2014年期间，标普500从84点升至2,059点，含再投资股息产生了第2页显示的11,196%总回报。同时，美元购买力惊人地下降了87%。这一降幅意味着现在需要1美元才能购买1965年可用13美分购买的东西（以消费者价格指数衡量）。</p><p>股票和美元之间这种悬殊表现向投资者传递了一个重要信息。回想我们2011年年度报告，我们将投资定义为&quot;现在将购买力转移给他人，并合理预期在将来——对名义收益缴纳税款后——获得更多购买力&quot;。</p><p>从过去五十年可以得出的非常规但不可避免的结论是，投资于美国企业的多元化组合远比投资于价值与美国货币挂钩的证券——例如国债——更安全。这在之前的半个世纪也是如此，该时期包括大萧条和两次世界大战。投资者应该重视这段历史。在某种程度上，这几乎肯定会在下个世纪重演。</p><p>股票价格总是比现金等价物波动大得多。然而，长期来看，以货币计价的工具是风险更高的投资——远比随时间买入并仅产生象征性费用和佣金的广泛多元化股票组合风险更高。这一教训通常未在商学院教授，那里几乎普遍将波动性作为风险的代理。虽然这一教学假设便于教学，但完全错误：波动性远非风险的同义词。将这两个术语等同的流行公式误导了学生、投资者和CEO。</p><p>当然，持有一天、一周或一年的股票确实比将资金留在现金等价物中风险更大（无论以名义还是购买力衡量）。这对某些投资者——例如投资银行——是相关的，其生存能力可能因资产价格下跌而受威胁，可能被迫在低迷市场出售证券。此外，任何近期可能有重大资金需求的方应在国债或受保存款中保持适当金额。</p><p>然而，对于能够——且应该——以数十年为视野投资的大多数投资者而言，报价下跌并不重要。他们的关注点应保持在投资生涯中获得购买力的显著增长。对他们而言，随时间买入的多元化股票组合将被证明远比以美元为基础的证券风险更低。</p><p>相反，如果投资者害怕价格波动，错误地将其视为风险衡量，他可能讽刺地最终做一些非常危险的事情。回想一下，如果愿意，六年前哀叹股票价格下跌并建议投资&quot;安全&quot;的国库券或银行存单的权威人士。听从这一布道的人现在只能从他们之前预期将为愉快退休提供资金的金额上赚取微薄利息。（标普500当时低于700点；现在约2,100点。）如果不是害怕毫无意义的价格波动，这些投资者本可以通过简单购买极低成本指数基金确保自己终身获得良好收入，其股息将逐年上升，本金也将增长（当然会有许多起伏）。</p><p>当然，投资者可以通过自身行为使股票所有权成为高风险。许多人确实如此。频繁交易、试图&quot;择时&quot;、多元化不足、向管理人和顾问支付高额且不必要的费用，以及使用借入资金，都可能摧毁终身股票持有者本应享受的体面回报。事实上，借入资金在投资者工具箱中没有位置：市场任何时候都可能发生任何事情。没有任何顾问、经济学家或电视评论员——查理和我绝对不是——能告诉您混乱何时发生。市场预测者会填满您的耳朵，但永远不会填满您的钱包。</p><p>上述投资罪行的实施不限于&quot;小人物&quot;。大型机构投资者作为一个群体，长期表现不如只是坐几十年的不老练指数基金投资者。一个主要原因是费用：许多机构向顾问支付大笔款项，顾问又推荐高费用管理人。这是一个傻瓜游戏。</p><p>当然，有少数投资管理人非常优秀——尽管短期内很难确定出色记录是源于运气还是天赋。然而，大多数顾问更擅长产生高额费用而非高额回报。事实上，他们的核心能力是推销术。投资者——无论大小——不应听他们的海妖之歌，而应阅读杰克·博格尔的《投资的常识小书》。</p><p>几十年前，本·格雷厄姆用莎士比亚的一段话指出了投资失败的根源：&quot;亲爱的布鲁图，过错不在我们的命运，而在我们自己。&quot;</p><hr><h2 id="年度大会" tabindex="-1">年度大会 <a class="header-anchor" href="#年度大会" aria-label="Permalink to &quot;年度大会&quot;">​</a></h2><p>年度大会将于5月2日星期六在CenturyLink中心举行。去年39,000人的出席创下纪录，我们预计今年随着庆祝金禧年将进一步增加。门7点开，请届时到场。</p><p>伯克希尔才华横溢的Carrie Sova将再次负责。Carrie六年前24岁时作为秘书加入我们。四年前，我请她负责大会——一项需要多种技能的巨大任务——她欣然接受。Carrie沉着冷静、足智多谋，善于激发数百名与她共事者的最佳表现。她得到我们整个总部的支持，大家乐于参与使这个周末对股东既有趣又有意义。</p><p>是的，我们也尝试向来访股东销售我们的产品。事实上，今年我们将大幅增加购物时间，CenturyLink周五5月1日中午至下午5点开放营业，以及大会日通常的上午7点至下午4点。所以让查理脸上露出笑容，认真购物。</p><p>周六早起。上午6:20，Norman和Jake——两头各重约一吨的德克萨斯长角牛——将沿第10街走向CenturyLink。Justin Boot的几位高管将骑在它们身上，他们兼任牛仔。跟在牛后面的是四匹马拉的富国银行驿站马车。伯克希尔已经销售飞机、火车和汽车。将牛和驿站马车加入我们的产品组合应该巩固我们作为美国全能运输公司的声誉。</p><p>周六约7:30，我们将举行第四届国际报纸投掷挑战赛。目标仍是Clayton Home的门廊，距离投掷线精确35英尺。我十几岁时——在我短暂尝试诚实劳动期间——投掷了约50万份报纸。所以我认为我相当不错。挑战我！羞辱我！打击我的傲气！任何投掷比我更接近门阶的人，我将为其购买一个Dilly Bar。报纸将36至42页，您必须自己折叠（不允许橡皮筋）。我将向12岁及以下表现最佳的参赛者颁发特别奖品。Deb Bosanek将担任裁判。</p><p>上午8:30，将放映一部新的伯克希尔电影。一小时后，我们将开始问答环节，（在CenturyLink摊位午餐休息后）持续至下午3:30。短暂休息后，查理和我将于下午3:45召开年度会议。该业务会议通常仅持续半小时左右。</p><p>您的购物场所将是毗邻会议的194,300平方英尺大厅，数十家伯克希尔子公司的产品将在那里出售。如果您周五没完成购物，趁查理周六讲话时溜出去，在我们的特价商品上狂欢。也看看精彩的BNSF铁路布局。尽管我已84岁，它仍让我兴奋。</p><p>去年您尽到了购物者的责任，我们大多数业务创下了销售纪录。周六九小时期间，我们售出1,385双Justin靴子（每23秒一双），13,440磅See&#39;s糖果，7,276双Wells Lamont工作手套和10,000瓶亨氏番茄酱。亨氏有一款新的芥末产品，今年芥末和番茄酱都将供应。（两者都买！）既然我们周五也开放营业，我们预计每个区域都将创新纪录。</p><p>Brooks——我们的跑鞋公司——将再次在大会上提供特别纪念鞋。购买一双后，第二天穿上参加我们第三届&quot;伯克希尔5K&quot;——上午8点从CenturyLink出发的跑步比赛。参与的全部详情将包含在随会议凭证寄给您的访客指南中。参赛者将发现自己在伯克希尔许多经理、董事和同事身旁跑步。（不过查理和我将睡懒觉。）</p><p>购物区的GEICO展台将由来自全国各地的公司顶级顾问值守。停下来获取报价。大多数情况下，GEICO能给您股东折扣（通常8%）。我们运营的51个司法管辖区中有44个允许这一特别优惠。（补充一点：如果您有资格获得其他折扣，如某些群体可获得的折扣，该折扣不叠加。）</p><p>带上您现有保险的详细信息，看看我们的价格。我们可以为许多人节省真金白银。</p><p>务必光顾书虫书店。它将携带约35本书和DVD，其中包括几个新标题。去年许多股东购买了Max Olson编纂的追溯至1965年的伯克希尔信件汇编，他为大会制作了更新版。我们还预计销售一本纪念我们五十周年的廉价书籍。目前仍在制作中，但我预期它将包含各种历史材料，包括19世纪的文件。</p><p>本报告所附代理材料的附件解释了您如何获得参加会议和其他活动所需的凭证。航空公司有时会提高伯克希尔周末的价格。如果您从远方来，比较飞往堪萨斯城与奥马哈的成本。两城市间车程约2½小时，堪萨斯城可能为您节省大量资金，尤其是如果您原计划在奥马哈租车。一对夫妇的节省可能超过1,000美元。把钱花在我们这里。</p><p>位于第72街Dodge和Pacific之间77英亩地块的内布拉斯加家具卖场（NFM），我们将再次提供&quot;伯克希尔周末&quot;折扣定价。去年会议期间的一周，该店创造了40,481,817美元的业务纪录。（NFM奥马哈店的平均周销售额约900万美元。）</p><p>要在NFM获得伯克希尔折扣，您必须在4月28日星期二至5月4日星期一期间购买，并出示会议凭证。该期间的特别定价甚至适用于几家通常严禁折扣的高端制造商的产品，但本着股东周末精神，他们为您破例。我们感谢他们的合作。NFM周一至周五上午10点至晚9点开放，周六上午10点至晚9:30，周日上午10点至晚8点。周六下午5:30至8点，NFM举办野餐，邀请您参加。</p><p>在波仙珠宝，我们将再次举办两项仅限股东的活动。第一项是5月1日星期五下午6点至9点的鸡尾酒会。第二项——主要盛会——将于5月3日星期日上午9点至下午4点举行。周六我们将开放至下午6点。近年来，我们三天的销量远超整个12月——通常是珠宝商最好的月份。</p><p>整个周末波仙珠宝将人潮涌动。因此为方便起见，股东价格将于4月27日星期一至5月9日星期六期间提供。在此期间，请出示会议凭证或显示您是伯克希尔持有人的经纪报表以确认股东身份。</p><p>周日，在波仙珠宝商场外，来自达拉斯的杰出魔术师Norman Beck将让围观者惊叹。此外，我们将有Bob Hamman和Sharon Osberg——两位世界顶级桥牌专家——周日下午与股东打桥牌。别跟他们赌钱。</p><p>我的朋友Ariel Hsing周日也将在商场接受乒乓球挑战。我九岁时认识她，即使那时我也无法从她身上拿下一分。现在，她已是普林斯顿大学大二学生，曾代表美国参加2012年奥运会。如果您不介意让自己难堪，从下午1点开始测试您的技能。比尔·盖茨和我将打头阵，试图让她心软。</p><p>Gorat&#39;s和Piccolo&#39;s将再次于5月3日周日仅向伯克希尔股东开放。两家都将营业至晚10点，Gorat&#39;s下午1点开门，Piccolo&#39;s下午4点开门。这些餐厅是我的最爱，我周日晚上将在两家用餐。记住：要在Gorat&#39;s预订，4月1日致电402-551-3733（但不要更早）；Piccolo&#39;s致电402-346-2865。在Piccolo&#39;s，点一份巨型根啤漂浮作为甜点。只有娘娘腔才点小份。</p><p>我们将再次由同样的三位财经记者主持大会问答环节，请查理和我回答股东通过电子邮件提交给他们的问题。记者及其电子邮件地址是：Carol Loomis，去年从财富杂志退休，六十年职业生涯，但仍是商业和财经事务专家，可电邮loomisbrk@gmail.com；CNBC的Becky Quick，BerkshireQuestions@cnbc.com；纽约时报的Andrew Ross Sorkin，arsorkin@nytimes.com。</p><p>从提交的问题中，每位记者将选择他或她认为最有趣和最重要的六个。记者告诉我，如果您的问题简洁、避免在最后时刻提交、与伯克希尔相关且在任何发送给他们的电子邮件中不超过两个问题，则被选中的机会最大。（在电子邮件中，让记者知道如果您的提问被问及，您是否希望提及姓名。）</p><p>我们还将有一个追踪伯克希尔的三位分析师小组。今年保险专家将是Dowling &amp; Partners的Gary Ransom。涉及我们非保险运营的问题将来自Ruane, Cunniff &amp; Goldfarb的Jonathan Brandt和Morningstar的Gregg Warren。我们希望分析师和记者提出有助于我们所有者理解和认识其投资的问题。</p><p>查理和我对即将到来的问题毫无线索。有些肯定很难，这正是我们喜欢的方式。我们预计总共至少54个问题，允许分析师和记者各六个，观众18个。（去年总共62个。）观众提问者将通过年会上午8:15进行的11次抽签选出。安装在竞技场和主溢流室的11个麦克风将各自——可以这么说——主持一次抽签。</p><p>在谈到我们所有者获取知识这一主题时，让我提醒您，查理和我认为所有股东应同时获得伯克希尔发布的新信息，并应有足够时间分析。这就是为什么我们尝试在周五晚或周六早发布财务数据，以及为什么我们的年度大会总是在周六举行。我们不与大型机构投资者或分析师一对一交谈，而是像对待所有其他股东一样对待他们。</p><hr><p>我们在大会期间得到奥马哈数以千计居民和企业的 terrific帮助，他们希望您玩得愉快。今年，因为预计出席人数创纪录，我们担心酒店房间短缺。为处理这一可能问题，Airbnb正特别努力获取会议期间周围的房源，可能提供广泛的住宿选择。Airbnb的服务对预计仅在奥马哈逗留一晚的股东可能尤其有帮助，他们知道去年少数酒店要求客人支付至少三晚费用。这很昂贵。预算紧张的人应查看Airbnb网站。</p><hr><p>有充分理由，我经常赞扬我们运营经理人的成就。他们确实是全明星，将业务运营得仿佛是其家族拥有的唯一资产。我相信我们经理人的心态也是大型上市公司中能找到的最以股东为导向的。我们大多数经理人没有经济需求工作。击出商业&quot;全垒打&quot;的喜悦对他们的意义不亚于薪水。</p><p>同样重要的是，与我们一同在公司办公室工作的24名男女。这一群体高效处理大量SEC和其他监管要求，提交24,100页联邦所得税申报表，监督3,400份州税申报表的提交，回应无数股东和媒体询问，发出年度报告，准备全国最大的年度大会，协调董事会活动——不胜枚举。</p><p>他们愉快且以难以置信的效率处理所有这些业务任务，使我的生活轻松愉快。他们的努力超越严格与伯克希尔相关的活动：去年他们处理了40所大学（从200名申请者中选出）派学生到奥马哈与我问答一天。他们也处理我收到的各种请求，安排我的旅行，甚至为我午餐买汉堡和薯条（当然涂满亨氏番茄酱）。没有CEO比我处境更好；我真的感觉每天跳着踢踏舞去上班。</p><p>去年，为年度报告，我们放弃了48年的&quot;无照片&quot;政策——谁说我不灵活？——刊登了我们出色的总部团队在圣诞午餐时拍摄的照片。我没预先警告这群人他们将公开露面，所以他们没穿盛装。今年情况不同：在对页您将看到当他们认为有人注意时这群人的样子。无论他们如何穿着，他们的表现令人难以置信。</p><p>5月2日来见他们，享受我们的资本家伍德斯托克。</p><p><strong>2015年2月27日</strong></p><p><strong>沃伦·E·巴菲特</strong><strong>董事会主席</strong></p><hr><h2 id="伯克希尔·哈撒韦公司收购标准" tabindex="-1">伯克希尔·哈撒韦公司收购标准 <a class="header-anchor" href="#伯克希尔·哈撒韦公司收购标准" aria-label="Permalink to &quot;伯克希尔·哈撒韦公司收购标准&quot;">​</a></h2><p>我们渴望从委托人或其代表处了解符合以下所有标准的企业：</p><ol><li>大型收购（税前利润至少7,500万美元，除非该业务能纳入我们现有单位之一），</li><li>展示了持续盈利能力（我们对未来预测不感兴趣，也不关注&quot;扭亏为盈&quot;情况），</li><li>在很少或没有债务的情况下获得良好股本回报的企业，</li><li>现有管理层（我们无法提供），</li><li>简单的业务（如果有大量技术，我们将无法理解），</li><li>合理的要价（当价格未知时，我们不想浪费我们或卖方的时间，即使初步讨论交易）。</li></ol><p>公司越大，我们的兴趣越大：我们希望进行50-200亿美元范围的收购。然而，我们对收到关于我们可能在普通股市进行的购买建议不感兴趣。</p><p>我们不会参与恶意收购。我们可以承诺完全保密和非常快速的答复——通常在五分钟内——关于我们是否感兴趣。我们更愿意用现金购买，但当我们获得的内在商业价值与我们付出的一样多时，会考虑发行股票。我们不参与拍卖。</p><p>查理和我经常收到不符合我们测试的收购提议：我们发现，如果您表达购买牧羊犬的兴趣，很多人会打电话希望卖给您他们的可卡犬。一首乡村歌曲的一句歌词表达了我们对新创企业、扭亏为盈或拍卖式出售的感觉：&quot;当电话不响时，你就知道是我。&quot;</p><hr><h2 id="伯克希尔——过去、现在和未来" tabindex="-1">伯克希尔——过去、现在和未来 <a class="header-anchor" href="#伯克希尔——过去、现在和未来" aria-label="Permalink to &quot;伯克希尔——过去、现在和未来&quot;">​</a></h2><h3 id="开端" tabindex="-1">开端 <a class="header-anchor" href="#开端" aria-label="Permalink to &quot;开端&quot;">​</a></h3><p>1964年5月6日，当时由一位名叫西伯里·斯坦顿的人运营的伯克希尔·哈撒韦公司向股东发出一封信，提议以每股11.375美元购买225,000股股票。我预料到这封信；我对价格感到惊讶。</p><p>伯克希尔当时有1,583,680股流通股。其中约7%由巴菲特合伙有限公司（&quot;BPL&quot;）持有——一个由我管理且我几乎全部净资产都在其中的投资实体。在要约发出前不久，斯坦顿曾问我BPL会以什么价格出售其持股。我回答11.50美元，他说：&quot;好，成交。&quot;然后来了伯克希尔的信，出价低八分之一点。我对斯坦顿的行为感到恼火，没有要约出售。</p><p>那是一个极其愚蠢的决定。</p><p>伯克希尔当时是一家陷入糟糕业务的北方纺织制造商。其运营的行业正在走下坡路——无论比喻还是字面上。而伯克希尔因各种原因无法改变航向。</p><p>即使该行业的问题早已被广泛理解，情况也是如此。伯克希尔自己的董事会1954年7月29日的会议纪要列出了严峻事实：&quot;新英格兰纺织工业四十年前开始衰退。战争年代这一趋势停止。该趋势必须继续，直到供需平衡。&quot;</p><p>那次董事会会议约一年后，伯克希尔精细纺纱联合公司和哈撒韦制造公司——两者均有19世纪渊源——联手，采用我们今天所承的名称。合并后的公司拥有十四家工厂和10,000名员工，成为新英格兰纺织业的巨头。然而，两位管理层视为合并协议的东西，很快演变为自杀契约。在合并后的七年里，伯克希尔整体亏损运营，净资产缩水37%。</p><p>同时，公司关闭了九家工厂，有时使用清算所得回购股票。这一模式引起了我的注意。</p><p>我于1962年12月购买BPL首批伯克希尔股票，预期会有更多关闭和更多回购。当时股票售价7.50美元，较每股10.25美元的运营资金和20.20美元的账面价值有大幅折让。以该价格购买股票就像捡起一个被丢弃的只剩一口的雪茄烟蒂。虽然烟蒂可能丑陋潮湿，但这口烟是免费的。一旦那一瞬间的快乐享受完毕，就不能再期待更多。</p><p>此后伯克希尔照本宣科：很快又关闭了两家工厂，在1964年5月的举措中，着手用关闭所得回购股票。斯坦顿提供的价格比我们原始购买成本高50%。就在那里——我的免费一口烟，等着我，之后我可以去别处寻找其他被丢弃的烟蒂。</p><p>相反，因对斯坦顿的斤斤计较感到恼火，我无视他的要约，开始积极购买更多伯克希尔股票。</p><p>到1965年4月，BPL持有392,633股（当时流通股1,017,547股），在5月初的董事会会议上我们正式取得公司控制权。因西伯里和我的幼稚行为——毕竟，八分之一点对我们任何一方算什么？——他丢了工作，而我发现自己将BPL超过25%的资本投入一个我所知甚少的糟糕业务。我成了那条追上汽车的狗。</p><p>由于伯克希尔的运营亏损和股票回购，其1964财年末净资产已从1955年合并时的5,500万美元降至2,200万美元。全部2,200万美元都被纺织业务占用：公司没有超额现金，欠银行250万美元。（伯克希尔1964年年度报告转载于第130-142页。）</p><p>有一段时间我运气不错：伯克希尔立即享受了两年的良好运营条件。更好的是，那些年的利润免缴所得税，因为它拥有因早年灾难性结果产生的大量亏损结转。</p><p>然后蜜月期结束。在1966年后的18年里，我们不懈地与纺织业务斗争，全无成效。但固执——愚蠢？——有其限度。1985年，我终于认输，关闭了运营。</p><hr><p>未被我对一个垂死业务投入BPL大量资源这一首次错误吓退，我迅速加重了错误。事实上，我的第二次失误比第一次严重得多，最终成为我职业生涯中代价最高的。</p><p>1967年初，我让伯克希尔支付860万美元购买国民赔偿公司（&quot;NICO&quot;），一家规模不大但有前途的奥马哈保险公司。（一家小型姊妹公司也包含在交易中。）保险是我的舒适区：我理解并喜欢这个行业。</p><p>NICO的所有者杰克·林沃特是一位老朋友，想卖给我——我个人。他的要约绝无意向伯克希尔。那么我为什么为伯克希尔而非BPL购买NICO？我有48年时间思考这个问题，仍未想出一个好答案。我只是犯了一个巨大的错误。</p><p>如果BPL是购买方，我的合伙人和我将100%拥有一家优秀企业，注定成为建立伯克希尔今日样貌的基础。此外，我们的增长将不会因近二十年囚禁在纺织业务中的非生产性资金而受阻。最后，我们随后的收购将由我的合伙人和我完全拥有，而非由伯克希尔的遗留股东39%拥有——我们对他们没有义务。尽管这些事实摆在眼前，我选择将一家优秀企业（NICO）100%嫁给一家61%拥有的糟糕企业（伯克希尔哈撒韦），这一决定最终将约1,000亿美元从BPL合伙人转移给一群陌生人。</p><hr><p>再坦白一次，然后我会转到更愉快的话题：你能相信我在1975年购买了Waumbec Mills——另一家新英格兰纺织公司吗？当然，购买价格基于我们获得的资产和与伯克希尔现有纺织业务预期的协同效应，是个&quot;便宜货&quot;。然而——意外，意外——Waumbec是场灾难，工厂没几年就不得不关闭。</p><p>现在一些好消息：北方纺织业终于灭绝。如果你听说我在新英格兰游荡，不必恐慌。</p><hr><h3 id="查理纠正了我" tabindex="-1">查理纠正了我 <a class="header-anchor" href="#查理纠正了我" aria-label="Permalink to &quot;查理纠正了我&quot;">​</a></h3><p>当我管理小额资金时，我的雪茄烟蒂策略运作良好。事实上，我在1950年代获得的数十次免费一口烟使那十年成为我一生中相对和绝对投资表现最好的时期。</p><p>即便那时，我对雪茄烟蒂也有一些例外，最重要的是GEICO。得益于1951年我与洛里默·戴维森——一位后来成为该公司CEO的出色人士——的交谈，我了解到GEICO是一家优秀企业，立即将我9,800美元净资产的65%投入其股票。不过，我早年的大部分收益来自以便宜价格交易的中等公司投资。本·格雷厄姆教会了我这一技巧，它奏效了。</p><p>但这一方法的一个主要弱点逐渐显现：雪茄烟蒂投资只能扩展到一定程度。对于大额资金，它永远不会运作良好。</p><p>此外，以便宜价格购买的边际企业作为短期投资可能有吸引力，但它们是建立大型持久企业的错误基础。选择婚姻伴侣显然比约会需要更苛刻的标准。（伯克希尔应该指出，会是一个高度满意的&quot;约会对象&quot;：如果我们接受西伯里·斯坦顿对我们股票11.375美元的要约，BPL对其伯克希尔投资的加权年回报将约为40%。）</p><hr><p>是查理·芒格打破了我的雪茄烟蒂习惯，为建立一家能结合巨大规模与满意利润的企业设定了航向。查理在离我现在住处几百英尺的地方长大，年轻时也像我一样在我祖父的杂货店工作。然而，直到1959年我才认识查理，那时他早已离开奥马哈，将洛杉矶作为家园。我当时28岁，他35岁。介绍我们认识的奥马哈医生预测我们会合得来——确实如此。</p><p>如果您参加过我们的年度大会，您知道查理具有广博的才华、惊人的记忆力和一些坚定的观点。我也并非摇摆不定，我们有时意见不一。然而，在56年里，我们从未有过争执。当我们不同时，查理通常以这句话结束对话：&quot;沃伦，想清楚，你会同意我，因为你聪明而我是对的。&quot;</p><p>你们大多数不知道的是，建筑是查理的热爱之一。虽然他开始职业生涯是执业律师（按每小时15美元计费时间），查理在30多岁时通过在洛杉矶附近设计和建造五个公寓项目赚到了第一笔真钱。同时，他设计了他今天居住的房子——55年后。（像我一样，查理如果对环境满意就不会被移动。）近年来，查理在斯坦福和密歇根大学设计了大型宿舍综合体，如今91岁，正在从事另一个重大项目。</p><p>从我的角度看，查理最重要的建筑壮举是设计了今日的伯克希尔。他给我的蓝图很简单：忘掉你所知道的以美好价格购买公平企业；相反，以公平价格购买美好企业。</p><p>改变我的行为并非易事（问我的家人）。没有查理的投入，我已享有相当的成功，为什么要听一位从未在商学院待过一天的律师（当——咳咳——我上过三所）。但查理从不厌倦向我重复他关于商业和投资的格言，其逻辑无可辩驳。因此，伯克希尔已按查理的蓝图建造。我的角色是总承包商，伯克希尔子公司的CEO作为分包商做真正的工作。</p><p>1972年是伯克希尔的转折点（尽管我偶有倒退——记得我1975年购买Waumbec）。当时我们有机会为Blue Chip Stamps购买See&#39;s Candy——一家查理、我和伯克希尔均有大股份的公司，后来并入伯克希尔。</p><p>See&#39;s是传奇的西海岸盒装巧克力制造商和零售商，当时年税前利润约400万美元，仅使用800万美元有形净资产。此外，公司有一项未出现在其资产负债表上的巨大资产：广泛持久的竞争优势，赋予其重大定价权。这一优势几乎肯定会使See&#39;s随时间获得重大利润增长。更好的是，这些增长只需少量增量投资。换言之，See&#39;s可预期在未来几十年大量产生现金。</p><p>控制See&#39;s的家族要价3,000万美元，查理正确地说它值那么多。但我不想付超过2,500万美元，即使那个数字我也不太热衷。（三倍有形净资产的价格让我倒吸一口凉气。）我的错误谨慎可能毁掉一次绝佳购买。但幸运的是，卖方决定接受我们2,500万美元的出价。</p><p>迄今，See&#39;s已产生19亿美元税前利润，其增长仅需追加投资4,000万美元。See&#39;s因此能够分配巨额资金，帮助伯克希尔购买其他业务，这些业务反过来又产生大量可分配利润。（想象兔子繁殖。）此外，通过观察See&#39;s的行动，我获得了关于强大品牌价值的企业教育，开阔了我对许多其他有利可图投资的眼界。</p><hr><p>即使有查理的蓝图，自Waumbec以来我仍犯了许多错误。最惨烈的是Dexter Shoe。1993年我们购买该公司时，它有出色记录，在我看来绝非雪茄烟蒂。然而，其竞争优势很快因外国竞争而蒸发。而我简直没有预见到。</p><p>因此，伯克希尔为Dexter支付4.33亿美元，其价值相当迅速归零。然而，GAAP会计远未记录我错误的程度。事实是我给Dexter卖方伯克希尔股票而非现金，我用于购买的股票现在价值约57亿美元。作为金融灾难，这一笔应在吉尼斯世界纪录中占有一席之地。</p><p>我随后的几个错误也涉及使用伯克希尔股票购买注定只能蹒跚前行的企业。这类错误是致命的。用一家美好企业——伯克希尔当然是——的股票交换一家平庸企业的所有权，不可修复地摧毁价值。</p><p>当伯克希尔持股的公司犯下这一错误时，我们也遭受财务损失（错误有时发生在我担任董事期间）。CEO们似乎常常对一个基本现实视而不见：您在收购中付出的股票的内在价值不得超过您获得的企业的内在价值。</p><p>我从未见过投资银行家在向潜在收购方董事会陈述股票换股票交易时量化这一至关重要的数学。相反，银行家的焦点将是描述当前收购支付的&quot;惯例&quot;市场溢价——一种绝对愚蠢的评估收购吸引力的方式——或交易是否会增加收购方每股收益（其本身远非决定性）。为达到期望的每股数字，气喘吁吁的CEO和他的&quot;帮手&quot;常会幻想出&quot;协同效应&quot;。（作为19家公司的董事多年，我从未听到提及&quot;负协同&quot;，尽管交易完成后我目睹大量此类情况。）收购事后剖析，将现实诚实地与原始预测比较，在美国董事会罕见。它们反而应是标准做法。</p><p>我可以向您保证，在我离开很久之后，伯克希尔的CEO和董事会将在任何收购发行股票前仔细进行内在价值计算。用一百美元钞票交换八个十美元不能致富（即使您的顾问给您一份昂贵的&quot;公允意见&quot;背书该交换）。</p><hr><p>总体而言，伯克希尔的收购运作良好——少数几笔大型收购非常好。我们在有价证券上的投资也是如此。后者在我们的资产负债表上始终按市价计值，因此任何收益——包括未实现收益——立即反映在我们的净资产中。但我们整体购买的企业从未在我们的资产负债表上重新估值上调，即使我们可能以数十亿美元高于其账面价值出售。伯克希尔子公司价值的未记录收益已变得巨大，过去十年增长尤其迅速。</p><p>听从查理已获得回报。</p><hr><h3 id="伯克希尔今日" tabindex="-1">伯克希尔今日 <a class="header-anchor" href="#伯克希尔今日" aria-label="Permalink to &quot;伯克希尔今日&quot;">​</a></h3><p>伯克希尔现在是一个庞大的企业集团，不断试图进一步扩张。</p><p>应该承认，企业集团在投资者中名声不佳。它们罪有应得。让我首先解释它们为何不受待见，然后描述为何企业集团形式给伯克希尔带来巨大而持久的优势。</p><p>自进入商业世界以来，企业集团经历了几个极度流行的时期，最愚蠢的发生在1960年代末。当时企业集团CEO的套路很简单：通过个性、宣传或可疑会计——通常三者并用——这些管理者将一家初创企业集团的股票推至比如20倍收益，然后尽快发行股票收购另一家以十倍左右收益出售的企业。他们立即对收购应用&quot;权益结合法&quot;会计——基础业务没有任何改变——自动增加每股收益，并以此作为管理天才的证明。他们接下来向投资者解释，这种才华证明维持甚至提高收购方市盈率倍数是合理的。最后，他们承诺无休止重复这一程序，从而创造不断增加的每股收益。</p><p>华尔街对这种戏法的迷恋随着1960年代的推进而加剧。华尔街的居民总是愿意暂停怀疑，当可疑手段用于制造上升的每股收益时，尤其是如果这些杂技产生为投资银行家带来巨额费用的合并。审计师乐意为企业集团的会计洒下圣水，有时甚至建议如何进一步夸大数字。对许多人来说，轻松金钱的喷涌冲刷了道德敏感。</p><p>由于扩张企业集团的每股收益增长来自利用市盈率差异，其CEO不得不寻找以低收益倍数出售的企业。这些当然典型是长期前景不佳的中等企业。这种底捞激励通常导致企业集团的基础业务组合变得越来越垃圾。这对投资者关系不大：他们看重的是交易速度和权益结合法会计带来的收益增加。</p><p>由此产生的合并活动风暴被奉承的媒体煽动。ITT、利顿工业、海湾与西方、LTV等公司被神化，其CEO成为名人。（这些曾经著名的企业集团现已消失。正如尤吉·贝拉所说，&quot;每个拿破仑都会遇到他的水门事件。&quot;）</p><p>当时，各种会计诡计——许多荒谬地透明——被原谅或忽视。事实上，让会计奇才掌舵扩张企业集团被视为巨大加分：在这些情况下，股东可以确信报告利润永远不会令人失望，无论业务的运营现实变得多么糟糕。</p><p>1960年代末，我参加了一次会议，一位好收购的CEO吹嘘他&quot;大胆、富有想象力的会计&quot;。大多数分析师以赞许的点头回应，认为自己找到了一位预测肯定能满足的管理者，无论业务结果如何。</p><p>然而，最终，午夜钟声敲响，一切都变成南瓜和老鼠。再次变得清楚，基于连续发行溢价股票的业务模式——就像连锁信模式——最肯定地重新分配财富，但绝不创造财富。不过，这两种现象在我国定期盛开——是每个推销员的梦想——尽管它们常以精心制作的伪装出现。结局总是一样：金钱从轻信者流向欺诈者。对于股票，不同于连锁信，被劫持的金额可能惊人。</p><p>在BPL和伯克希尔，我们从未投资于热衷发行股票的公司。这种行为是推销导向管理层、薄弱会计、溢价股票——且常常——彻头彻尾不诚实的最可靠指标之一。</p><hr><p>那么查理和我觉得伯克希尔的企业集团结构有何如此吸引力？简单地说：如果审慎使用企业集团形式，它是最大化长期资本增长的理想结构。</p><p>资本主义备受赞颂的美德之一是它有效配置资金。论点是市场将投资引向有前途的企业，拒绝注定凋零的企业。这是真的：尽管有各种过度，市场驱动的资本配置通常远优于任何替代方案。</p><p>然而，理性资本流动常有障碍。正如那些1954年伯克希尔会议纪要清楚表明，纺织业内本应明显的资本撤回因管理层的虚妄希望和自身利益而推迟数十年。事实上，我自己也拖延太久才放弃我们过时的纺织厂。</p><p>将资本部署在衰退运营中的CEO很少选择将该资本大规模重新部署到无关活动。这种举措通常要求解雇长期同事并承认错误。此外，即使他或她倾向于承担，也不太可能CEO是您希望负责重新部署工作的管理者。</p><p>在股东层面，当个人投资者试图在企业与行业间重新配置资本时，税收和摩擦成本沉重。即使免税机构投资者在移动资本时也面临重大成本，因为它们通常需要中介做这项工作。许多口味昂贵的嘴巴然后叫嚷着要被喂养——其中包括投资银行家、会计师、顾问、律师和杠杆收购运营商等资本重新配置者。洗牌者不便宜。</p><p>相比之下，像伯克希尔这样的企业集团完全有条件以最小成本理性配置资本。当然，形式本身不保证成功：我们犯了许多错误，还会犯更多。然而，我们的结构性优势是强大的。</p><p>在伯克希尔，我们可以——不招致税收或太多其他成本——将巨额资金从增量投资机会有限的企业移动到前景更大的其他板块。此外，我们不受因终身与特定行业相关而产生的历史偏见束缚，也不受有既得利益维持现状的同事压力。这很重要：如果马控制投资决策，就不会有汽车工业。</p><p>我们拥有的另一个主要优势是能够购买优秀企业的片段——又名普通股。这对大多数管理层不是可行之道。在我们的历史上，这一战略替代证明非常有帮助；广泛的选项范围总是改善决策制定。股市每天向我们提供的企业——确实以小片段形式——往往比我们同时被整体报价的企业更有吸引力。此外，我们从有价证券实现的收益帮助我们进行了某些否则将超出我们财务能力的大型收购。</p><p>实际上，世界是伯克希尔的牡蛎——一个向我们提供远超大多数公司现实可得机会范围的世界。当然，我们限于我们能评估其经济前景的企业。这是一个严重限制：查理和我不知道许多公司十年后会是什么样。但这一限制远小于一位经验限于单一行业的高管所承受的限制。此外，我们可以有利地扩展到远大于许多受限于其所运营单一行业有限潜力的企业的规模。</p><p>我之前提到See&#39;s Candy产生了与其适度资本要求相比的巨额利润。当然，我们会乐于明智地使用这些资金扩大我们的糖果业务。但我们这样做的许多尝试基本失败。所以，在不招致税收低效或摩擦成本的情况下，我们用See&#39;s产生的超额资金帮助购买其他企业。如果See&#39;s仍是独立公司，其利润将不得不分配给投资者重新部署，有时在大量税收和几乎总是显著的摩擦和代理成本后严重损耗。</p><hr><p>伯克希尔还有一个近年来变得日益重要的优势：我们现在是许多杰出企业所有者和管理者的归宿之选。</p><p>拥有成功企业的家族在考虑出售时有多种选择。通常，最佳决定是什么都不做。拥有一家自己深刻理解的繁荣企业，生活中有更糟的事情。但坐以待毙很少是华尔街推荐的。（别问理发师您是否需要理发。）</p><p>当家族一部分希望出售而其他人希望继续时，公开发行常有意义。但当所有者希望完全套现时，他们通常考虑两条路径之一。</p><p>第一条是出售给对从两家公司合并中榨取&quot;协同效应&quot;垂涎三尺的竞争对手。这种买方不可避免地考虑裁减卖方大量同事——正是那些帮助所有者建立其企业的人。然而，一位有爱心的所有者——这样的有很多——通常不想让他的长期同事悲惨地唱着那首老乡村歌曲：&quot;她得到了金矿，我得到了竖井。&quot;</p><p>卖方的第二条选择是华尔街买方。多年来，这些买方准确地自称为&quot;杠杆收购公司&quot;。当该术语在1990年代初获得恶名——记得RJR和《门口的野蛮人》？——这些买方匆忙重新贴标签为&quot;私募股权&quot;。</p><p>名称可能变了，但仅此而已：在几乎所有私募股权购买中，股权急剧减少，债务堆积如山。事实上，私募股权买方提供给卖方的金额部分由买方评估可置于被收购公司上的最大债务额决定。</p><p>后来，如果情况顺利且股权开始建立，杠杆收购店常会寻求用新借款重新杠杆化。然后它们典型地使用部分收益支付巨额股息，使股权急剧下降，有时甚至降至负数。</p><p>事实上，&quot;股权&quot;对许多私募股权买方是脏词；他们爱的是债务。而且，因为债务目前如此便宜，这些买方常能支付最高价。后来，企业将被转售，常给另一个杠杆买方。实际上，企业变成一件商品。</p><p>伯克希尔向希望出售的企业所有者提供第三种选择：一个永久家园，在那里公司的人员和文化将被保留（虽然偶尔需要管理层变动）。此外，我们收购的任何企业都大幅增强其财务实力和增长能力。它与银行和华尔街分析师打交道的日子也永远结束。</p><p>有些卖方不在乎这些事情。但当卖方确实在乎时，伯克希尔没有很多竞争。</p><hr><p>有时权威建议伯克希尔分拆某些业务。这些建议毫无意义。我们的公司作为伯克希尔的一部分比作为独立实体更有价值。一个原因是我们能够立即且免税地在业务之间或进入新风险转移资金。此外，如果运营分离，某些成本会全部或部分重复。最明显的例子：伯克希尔为其单一董事会产生名义成本；如果我们数十家子公司被分拆，董事整体成本将飙升。监管和行政支出也将如此。</p><p>最后，因为我们拥有子公司B，子公司A有时有重要的税收效率。例如，我们的公用事业可获得的某些税收抵免目前仅因我们在其他伯克希尔运营产生巨额应税收入才可实现。这使伯克希尔哈撒韦能源在开发风能和太阳能项目上较大多数公用事业公司有重大优势。</p><p>投资银行家因行动而获得报酬，不断催促收购方为公众持股企业支付20%至50%的市场溢价。银行家告诉买方，溢价因&quot;控制价值&quot;及收购方CEO接管后将要发生的美好事情而合理。（哪位渴望收购的经理会质疑这一断言？）</p><p>几年后，银行家——板着脸——再次出现，同样诚恳地催促分拆之前的收购以&quot;释放股东价值&quot;。当然，分拆剥夺拥有公司其所谓的&quot;控制价值&quot;而没有任何补偿付款。银行家解释，分拆公司将蓬勃发展，因为其管理层将更具创业精神，从母公司的窒息官僚中解放出来。（早些时候我们遇到的那位有才华的CEO去哪了？）</p><p>如果剥离公司后来希望重新收购分拆的运营，据推测又将受到其银行家催促支付可观的&quot;控制&quot;溢价以获得该特权。（银行界这种心理&quot;灵活性&quot;促使了这一说法：费用太常导致交易而非交易导致费用。）</p><p>当然，可能有一天伯克希尔的分拆或出售将被监管机构要求。伯克希尔在1979年进行了这种分拆，当时银行控股公司新法规迫使我们剥离在伊利诺伊州罗克福德拥有的一家银行。</p><p>不过，自愿分拆对我们毫无意义：我们将失去控制价值、资本配置灵活性，以及在某些情况下重要的税收优势。现在出色运营我们子公司的CEO如果运营分拆实体，考虑到从伯克希尔所有权衍生的运营和财务优势，将难以同样有效。此外，母公司和分拆运营一旦分离，可能产生比合并时略高的成本。</p><hr><p>在离开分拆主题前，让我们看看从早先提到的一家企业集团得到的教训：LTV。我在此总结，但那些喜欢精彩金融故事的人应阅读1982年10月D杂志上关于Jimmy Ling的文章。在互联网上查找。</p><p>通过大量企业花招，Ling将LTV从1965年仅3,600万美元销售额带到仅两年后财富500强第14位。应该指出，Ling从未展示任何管理技能。但查理很久以前告诉我，永远不要低估高估自己的人。在这方面Ling无与伦比。</p><p>Ling的战略——他标记为&quot;项目重新部署&quot;——是购买一家大公司然后部分分拆其各个部门。在LTV 1966年年度报告中，他解释将随之而来的魔力：&quot;最重要的是，收购必须通过2加2等于5（或6）公式的测试。&quot;媒体、公众和华尔街喜欢这种谈话。</p><p>1967年Ling购买了Wilson &amp; Co.——一家巨大的肉类加工商，也涉足高尔夫设备和制药。不久后，他将母公司分成三家企业：Wilson &amp; Co.（肉类加工）、Wilson Sporting Goods和Wilson Pharmaceuticals，每家都将部分分拆。这些公司很快在华尔街被称为Meatball、Golf Ball和Goof Ball。</p><p>不久后，像伊卡洛斯一样，Ling飞得离太阳太近。到1970年代初，Ling的帝国正在融化，他本人也被从LTV分拆……即被解雇。</p><p>金融市场定期会脱离现实——您可以指望这一点。更多Jimmy Ling将出现。他们看起来和听起来权威。媒体将挂在他们的每一个字上。银行家将为他们的业务争斗。他们所说的最近&quot;奏效&quot;了。他们的早期追随者将感觉自己很聪明。我们的建议：无论他们说什么，永远记住2加2总是等于4。当有人告诉您这数学多么过时——拉上钱包，度个假，几年后回来以便宜价格买股票。</p><hr><p>今天伯克希尔拥有：（1）无与伦比的企业集合，其中大多数现在享有有利的经济前景；（2）一群杰出的经理，除少数例外，异常致力于他们运营的子公司和伯克希尔；（3）非凡的利润多样性、卓越的财务实力和在所有情况下我们将保持的流动性海洋；（4）在许多考虑出售企业的所有者和管理者中的首选地位；（5）与一点相关的前一项，一种文化——在许多方面不同于大多数大公司——我们50年来努力发展，现已坚如磐石。</p><p>这些优势为我们提供了一个建设的美妙基础。</p><hr><h3 id="伯克希尔未来50年" tabindex="-1">伯克希尔未来50年 <a class="header-anchor" href="#伯克希尔未来50年" aria-label="Permalink to &quot;伯克希尔未来50年&quot;">​</a></h3><p>现在让我们看看前方的道路。请记住，如果50年前我试图预测即将发生什么，我的某些预测将大错特错。带着这一警告，我将告诉您今天如果我的家人问我伯克希尔的未来我会说什么。</p><p><strong>• 首先且绝对最重要的是，我相信耐心的伯克希尔股东遭受永久资本损失的机会在单公司投资中可找到的最低之列。这是因为我们的每股内在商业价值几乎肯定会随时间提升。</strong></p><p>这一乐观预测伴随着一个重要警告：如果投资者进入伯克希尔股票的点异常高——比如价格接近账面价值两倍，伯克希尔股票偶尔达到的水平——可能许多年后投资者才能实现利润。换言之，如果以抬高价格购买，稳健投资可能变成鲁莽投机。伯克希尔不豁免这一真理。</p><p>投资者以略高于公司将回购其股票水平的价格购买伯克希尔，但应在合理时间内产生收益。伯克希尔的董事将仅在他们认为远低于内在价值的价格授权回购。（在我们看来，这是回购的基本标准，常被其他管理层忽视。）</p><p>对于计划在购买后一两年内出售的投资者，无论入场价格如何，我无法提供任何保证。在此类缩短期内，一般股市的走势可能比伯克希尔股票内在价值的相应变化对您的结果重要得多。正如本·格雷厄姆几十年前所说：&quot;短期内市场是投票机；长期它是称重机。&quot;偶尔，投资者的投票决定——业余和专业 alike——近乎疯狂。</p><p>既然我不知道可靠预测市场走势的方法，我建议您仅在预期持有至少五年的情况下购买伯克希尔股票。那些寻求短期利润的人应另寻他处。</p><p>另一个警告：伯克希尔股票不应以借入资金购买。自1965年以来已有三次我们的股票从高点下跌约50%。某天，接近这种幅度的下跌将再次发生，没人知道何时。伯克希尔几乎肯定是投资者的满意持有。但对使用杠杆的投机者可能是灾难性选择。</p><p><strong>• 我相信任何事件导致伯克希尔经历财务问题的机会基本为零。我们将永远为千年一遇的洪水做好准备；事实上，如果它发生，我们将向未准备者出售救生衣。伯克希尔在2008-2009年崩溃期间作为&quot;第一响应者&quot;发挥了重要作用，此后我们的资产负债表和盈利潜力翻了一倍多。您的公司是美国商业的直布罗陀，将保持如此。</strong></p><p>财务持久力要求公司在所有情况下保持三种优势：（1）巨大可靠的利润流；（2）大量流动资产；（3）无重大近期现金需求。忽视最后一项必要条件通常导致公司经历意外问题：太多时候，盈利公司的CEO觉得他们将总是能够偿还到期债务，无论多大。2008-2009年，许多管理层了解了这种心态多么危险。</p><p>以下是我们将如何始终站在三项基本之上。首先，我们的利润流巨大，来自广阔的企业阵列。我们的股东现在拥有许多具有持久竞争优势的大公司，未来我们将收购更多。我们的多元化确保伯克希尔的持续盈利，即使灾难造成保险损失远超任何之前经历。</p><p>接下来是现金。在健康企业，现金有时被视为应最小化的东西——作为像股本回报这样标记的拖累的非生产性资产。然而，现金对企业就像氧气对个人：存在时从不考虑，缺席时唯一在心的东西。</p><p>美国企业在2008年提供了一个案例研究。那年9月，许多长期繁荣的公司突然想知道他们的支票在接下来的日子里是否会跳票。一夜之间，他们的财务氧气消失了。</p><p>在伯克希尔，我们的&quot;呼吸&quot;未中断。事实上，在跨越2008年9月下旬和10月上旬的三周内，我们向美国企业提供了156亿美元新鲜资金。</p><p>我们能做到这一点是因为我们总是保持至少200亿美元——通常远多——的现金等价物。我们指的是美国国库券，而非其他声称提供流动性且确实如此——除非真正需要——的现金替代品。票据到期时，只有现金是法定货币。不要不带它离家。</p><p>最后——谈到我们的第三点——我们永远不会从事可能导致突然需要大笔资金的运营或投资实践。这意味着我们不会使伯克希尔面临大额短期债务到期或进入可能要求大量抵押催缴的衍生合约或其他商业安排。</p><p>几年前，我们成为某些我们认为严重错误定价且仅有少量抵押要求的衍生合约的一方。这些证明相当有利可图。然而，最近，新写的衍生合约要求全额抵押。这结束了我们对衍生品的兴趣，无论它们可能提供什么利润潜力。多年来我们未写过这些合约，除了我们公用事业业务运营所需的少数。</p><p>此外，我们不会承保赋予保单持有人选择兑现权利的保险合约。许多人寿保险产品包含赎回特征，使其在极端恐慌时期易受&quot;挤兑&quot;影响。然而，此类合约在我们栖身的财产意外险世界不存在。如果我们的保费量萎缩，我们的浮存金将下降——但仅以非常缓慢的速度。</p><p>我们保守的原因——可能给一些人留下极端印象——是完全可以预测人们偶尔会恐慌，但完全不可预测这何时发生。虽然几乎每一天都相对平静，明天总是不确定。（我在1941年12月6日或2001年9月10日未感到特别忧虑。）如果您无法预测明天将带来什么，您必须为它带来的任何事做好准备。</p><p>计划64岁退休的CEO在评估给定年份仅有微小发生机会的风险时可能有自己的特殊计算。事实上，他可能99%的时间&quot;正确&quot;。然而，这些几率对我们没有吸引力。我们将永远不会用您托付给我们的资金玩金融俄罗斯轮盘赌，即使隐喻的枪有100个弹膛且仅一颗子弹。在我们看来，冒着失去您所需的风险去追求您仅仅想要的东西是疯狂。</p><p><strong>• 尽管我们保守，我认为我们每年都能建立伯克希尔的潜在每股盈利能力。这并不意味着运营利润每年都会增加——远非如此。美国经济将起伏——尽管主要是起——当它减弱时，我们当前的利润也将减弱。但我们将继续实现有机增长、进行补强收购并进入新领域。因此，我相信伯克希尔将每年增加其潜在盈利能力。</strong></p><p>有些年份增长将可观，其他时候较小。市场、竞争和机会将决定机会何时来到我们面前。贯穿这一切，伯克希尔将继续前进，由我们现在拥有的稳固企业阵列和我们将购买的新公司驱动。此外，在大多数年份，我国经济将为业务提供强劲顺风。我们很幸运以美国为家场。</p><p><strong>• 坏消息是，伯克希尔的长期收益——以百分比而非美元衡量——不能显著，也不会接近过去50年实现的。数字已变得太大。</strong></p><p>我认为伯克希尔将超越美国平均公司，但我们的优势（如果有）不会很大。</p><p>最终——大概十到二十年后——伯克希尔的利润和资本资源将达到不允许管理层明智地将公司全部利润再投资的水平。届时，我们的董事将需要确定分配超额利润的最佳方法是通过股息、股票回购还是两者兼有。如果伯克希尔股票以低于内在商业价值出售，大规模回购几乎肯定是最佳选择。您可以放心，您的董事将做出正确决定。</p><p><strong>• 没有公司会比伯克希尔更以股东为导向。三十多年来，我们每年重申我们的股东原则（见第117页），总是以：&quot;虽然我们的形式是公司，我们的态度是合伙关系&quot;开始。这一与您的契约刻在石头上。</strong></p><p>我们有一个极其知识渊博且以商业为导向的董事会准备履行合伙关系的承诺。没人为了钱接受这份工作：在几乎其他地方不存在的安排中，我们的董事仅收取象征性费用。他们通过拥有伯克希尔股票和作为重要企业良好管家的满足感获得回报。</p><p>他们及其家族拥有的股票——在许多情况下价值非常可观——是在市场购买的（而非通过期权或赠予变现）。此外，与几乎所有其他大型公众公司不同，我们不购买董事和高管责任保险。在伯克希尔，董事穿着您的鞋子走。</p><p>为确保我们文化的延续，我建议我的儿子霍华德作为非执行董事长接替我。我这一愿望的唯一理由是，如果雇佣了错误的CEO且需要董事长果断行动，使变革更容易。我可以向您保证，这一问题在伯克希尔发生的概率非常低——可能像任何公众公司一样低。然而，在我担任十九家公众公司董事期间，我看到了如果平庸CEO也是董事长，替换他有多难。（事情通常做了，但几乎总是很晚。）</p><p>如果当选，霍华德将不获报酬，除了所有董事所需外，不花时间工作。他只是一个安全阀，任何董事如果对CEO有顾虑并希望了解其他董事是否也表达疑虑，可以去找他。如果多位董事忧虑，霍华德的董事长职位将使问题得到及时妥善处理。</p><p><strong>• 选择正确的CEO至关重要，是伯克希尔董事会会议大量时间的主题。管理伯克希尔主要是资本配置工作，加上选择和留住出色经理掌舵我们运营子公司。显然，这项工作也要求在需要时更换子公司的CEO。这些职责要求伯克希尔的CEO是理性、冷静、果断的个人，对商业有广泛理解，对人类行为有良好洞察。同样重要的是他知道自己局限。（正如IBM的Tom Watson, Sr.所说，&quot;我不是天才，但我在某些地方聪明，我待在这些地方。&quot;）</strong></p><p>品格至关重要：伯克希尔CEO必须为公司&quot;全情投入&quot;，而非为自己。（我用男性代词避免措辞尴尬，但性别永远不应决定谁成为CEO。）他不可避免地赚取远超任何可能需要的钱。但重要的是，既非自负也非贪婪驱使他追求与其最慷慨薪酬的同侪匹配的薪酬，即使他的成就远超他们。CEO的行为对下级经理有巨大影响：如果他们清楚股东利益对他最重要，他们也将——除少数例外——拥抱这种思维方式。</p><p>我的继任者需要另一个特殊优势：对抗企业衰败ABC的能力——即傲慢、官僚和自满。当这些企业癌症转移时，即使最强大的公司也可能动摇。证明这一点的例子不胜枚举，但为维持友谊，我将只挖掘遥远过去的案例。</p><p>在其辉煌岁月，通用汽车、IBM、西尔斯罗巴克和美国钢铁雄踞巨大行业。其实力似乎不可动摇。但我痛斥的破坏行为最终导致它们跌至CEO和董事不久前认为不可能的深度。它们曾经的财务实力和历史盈利能力证明无防御。</p><p>只有警惕和坚定的CEO才能在伯克希尔日益壮大时抵御这种削弱力量。他必须永远记住查理的恳求：&quot;告诉我将在哪里死，这样我就永远不去那里。&quot;如果我们非经济价值丧失，伯克希尔的大部分经济价值也将崩溃。&quot;高层风气&quot;将是维持伯克希尔特殊文化的关键。</p><p>幸运的是，我们未来CEO成功所需的结构已牢固到位。伯克希尔现存的非凡授权是官僚主义的理想解毒剂。在运营意义上，伯克希尔不是一家巨头公司，而是大公司的集合。在总部，我们从未有委员会，也从未要求子公司提交预算（尽管许多将其作为重要内部工具）。我们没有法律部门或其他公司视为理所当然的部门：人力资源、公共关系、投资者关系、战略、收购，您说得出。</p><p>当然，我们有活跃的审计职能；不做该死的傻瓜。然而，在异常程度上，我们信任我们的经理以强烈的管家意识运营。毕竟，在我们收购其业务前，他们正是那样做的。此外，除偶尔例外，我们的信任产生比一连串指令、无尽审查和层层官僚更好的结果。查理和我尝试以我们希望的方式与经理互动，如果位置互换。</p><p><strong>• 我们的董事相信，我们未来的CEO应来自伯克希尔董事会已深入了解的内部候选人。我们的董事还相信，新任CEO应相对年轻，以便他或她能在工作上长期任职。伯克希尔如果CEO平均掌舵超过十年将运作最佳。（很难教老狗新把戏。）而且他们也不太可能在65岁退休（或者您没注意到？）。</strong></p><p>在伯克希尔的企业收购和大型定制投资举措中，重要的是我们的对手方既熟悉又对伯克希尔的CEO感到舒适。建立那种信心和巩固关系需要时间。然而，回报可能巨大。</p><p>董事会和我都相信我们现在有合适的人选接替我担任CEO——一位在我去世或卸任后第二天就能承担工作的继任者。在某些重要方面，此人将比我做得更好。</p><p><strong>• 投资对伯克希尔永远至关重要，将由几位专家处理。他们将向CEO报告，因为他们的投资决策在广泛意义上需要与伯克希尔的运营和收购计划协调。不过总体而言，我们的投资经理将享有很大自主权。在这一领域，我们也为未来几十年做好充分准备。Todd Combs和Ted Weschler——各自在伯克希尔投资团队待了几年——在各方面都是一流的，可以在评估收购方面为CEO提供特别帮助。</strong></p><p>总之，伯克希尔在查理和我离开舞台后处于理想位置。我们有合适的人选——合适的董事、经理和这些经理的预期继任者。此外，我们的文化嵌入其各级。我们的系统也是再生的。在很大程度上，好文化和坏文化都自我选择以延续自身。出于很好理由，价值观与我们相似的企业所有者和运营经理将继续被吸引到伯克希尔作为一个独特和永久的家园。</p><p><strong>• 如果我不向使伯克希尔特别的另一个关键群体致敬，那就是我们的股东。伯克希尔确实拥有不同于任何其他巨头公司的所有者基础。这一事实在去年年度大会上得到充分展示，股东被提供一项代理决议：</strong></p><p><strong>决议：鉴于公司拥有超过所需的资金，且所有者不像沃伦那样是亿万富翁，董事会应考虑支付有意义的年度股息。</strong></p><p>该决议的发起股东未出席会议，因此其动议未正式提议。不过，代理投票已统计，结果令人启发。</p><p>不出所料，A类股——由相对少数股东持有，每人有重大经济利益——以89比1的差距对股息问题投&quot;反对&quot;票。</p><p>非凡的是我们B类股东的投票。他们数以十万计——也许总计一百万——他们投了660,759,855票&quot;反对&quot;和13,927,026票&quot;赞成&quot;，比例约47比1。</p><p>我们的董事建议投&quot;反对&quot;，但公司未以其他方式试图影响股东。然而，98%的投票股份实际上说，&quot;别给我们股息，而是将所有利润再投资。&quot;让我们的共同所有者——无论大小——如此与我们的管理哲学同步，既非凡又有回报。</p><p>我很幸运有你们作为合伙人。</p><p><strong>沃伦·E·巴菲特</strong></p><hr><h2 id="副董事长思考——过去与未来" tabindex="-1">副董事长思考——过去与未来 <a class="header-anchor" href="#副董事长思考——过去与未来" aria-label="Permalink to &quot;副董事长思考——过去与未来&quot;">​</a></h2><p><strong>致伯克希尔·哈撒韦公司股东：</strong></p><p>我密切观察了伯克希尔在沃伦·巴菲特领导下50年非凡成功的历史。现在似乎适宜我独立补充任何来自他的庆祝评论。我将尝试做五件事。</p><p>(1) 描述导致一家小且注定无法挽救的商品纺织业务变形为今日存在的强大伯克希尔的管理系统和政策，</p><p>(2) 解释该管理系统和政策是如何形成的，</p><p>(3) 解释在某种程度上伯克希尔为何做得这么好，</p><p>(4) 预测如果巴菲特不久离开，异常好的结果是否会继续，</p><p>(5) 考虑伯克希尔过去50年的伟大结果是否有别处可能证明有用的含义。</p><p>巴菲特领导下的伯克希尔的管理系统和政策（以下统称&quot;伯克希尔系统&quot;）很早就固定下来，描述如下：</p><p>(1) 伯克希尔将是一个分散的企业集团，仅回避那些无法做出有用预测的活动。</p><p>(2) 其顶层公司将几乎全部通过独立注册的子公司开展业务，这些子公司的CEO将以非常极端的自主权运营。</p><p>(3) 企业集团总部几乎什么都没有，除了一间包含董事长、CFO和少数主要帮助CFO进行审计、内控等的小办公室套间。</p><p>(4) 伯克希尔子公司将始终突出包括意外险保险人。这些保险人作为一个群体将被预期在适当时候产生可靠的承保收益，同时也产生大量用于投资的&quot;浮存金&quot;（来自未付保险负债）。</p><p>(5) 不会有重大的全系统人事制度、股票期权制度、其他激励制度、退休制度等，因为子公司将有自己的制度，通常不同。</p><p>(6) 伯克希尔的董事长将仅为自己保留少数活动。</p><p>(i) 他将管理几乎所有的证券投资，这些通常位于伯克希尔的意外险保险人中。</p><p>(ii) 他将选择所有重要子公司的CEO，确定其薪酬，并从每位那里获得突然需要时的继任者私人推荐。</p><p>(iii) 他将在子公司增加其竞争优势后部署子公司不需要的大部分现金，理想部署是用该现金收购新子公司。</p><p>(iv) 他将使自己几乎随时可供任何子公司CEO想要的联系，且他将要求几乎无额外联系。</p><p>(v) 他将为年度报告撰写一封长、逻辑且有用的信，设计为如果他是被动股东他会希望的样子，并将在年度股东大会回答数小时问题。</p><p>(vi) 他将努力成为在长期对客户、股东和其他利益相关者运作良好的文化的典范，无论在他离开前后。</p><p>(vii) 他的首要任务将是预留大量时间安静阅读和思考，特别是可能推进他坚定学习的内容，无论他变得多老；以及</p><p>(viii) 他还将花大量时间热情钦佩他人正在完成的事情。</p><p>(7) 新子公司通常将以现金而非新发行股票购买。</p><p>(8) 只要留存收益为股东创造超过一美元的市场价值，伯克希尔就不会支付股息。</p><p>(9) 在购买新子公司时，伯克希尔将寻求为董事长能相当好理解的良好业务支付公平价格。伯克希尔还将希望有好的CEO在位，预期长期留任且无需总部帮助就能管理好。</p><p>(10) 在选择子公司CEO时，伯克希尔将努力确保可靠性、技能、精力和对CEO所在业务和环境的热爱。</p><p>(11) 作为首选行为的重要事项，伯克希尔几乎永远不会出售子公司。</p><p>(12) 伯克希尔几乎永远不会将子公司的CEO转移到另一个无关子公司。</p><p>(13) 伯克希尔永远不会仅因年龄强制子公司CEO退休。</p><p>(14) 伯克希尔将很少有未偿债务，因为它试图维持(i)所有情况下几乎完美的信誉和(ii)在呈现异常机会时现金和信贷的易得性。</p><p>(15) 伯克希尔将始终对大企业的潜在卖方友好。此类企业的要约将得到迅速关注。如果不导致交易，伯克希尔除董事长和一两人外无人会知道该要约。且他们永远不会告诉外人。</p><p>伯克希尔系统的要素及其集合规模相当不寻常。我知道没有其他大公司有一半此类要素到位。</p><p>伯克希尔碰巧获得如此不同于常规的企业个性是怎么回事？</p><p>嗯，巴菲特即使仅34岁时就控制伯克希尔约45%的股份，且被所有其他大股东完全信任。他可以安装他想要的任何系统。他这样做了，创造了伯克希尔系统。</p><p>几乎每个要素都是因为巴菲特相信在他领导下将有助于最大化伯克希尔的成就而选择。他并非试图为其他公司创建一种放之四海而皆准的系统。事实上，伯克希尔的子公司在其自身运营中未被要求使用伯克希尔系统。有些在使用不同系统时蓬勃发展。</p><p>巴菲特设计伯克希尔系统时瞄准什么？</p><p>嗯，多年来我诊断出几个重要主题：</p><p>(1) 他特别希望持续最大化系统中最重要人员的理性、技能和奉献，从他自己开始。</p><p>(2) 他希望到处都是双赢结果——例如通过给予忠诚获得忠诚。</p><p>(3) 他希望最大化长期结果的决策，从通常在位足够长时间承担决策后果的决策者那里寻求这些。</p><p>(4) 他希望最小化总部大官僚几乎不可避免的坏影响。</p><p>(5) 他希望像本·格雷厄姆教授那样个人贡献于所获智慧的传播。</p><p>当巴菲特发展伯克希尔系统时，他预见所有随之而来的好处了吗？没有。巴菲特通过实践演进偶然发现一些好处。但当他看到有用后果时，他加强了其原因。</p><p>伯克希尔在巴菲特领导下为何做得这么好？</p><p>我只想到四个大因素：</p><p>(1) 巴菲特的建设性特质，</p><p>(2) 伯克希尔系统的建设性特质，</p><p>(3) 好运气，以及</p><p>(4) 一些股东和其他仰慕者——包括媒体中一些——的奇怪强烈、有感染力的奉献。</p><p>我相信所有四个因素都存在且有助益。但重担由建设性特质、奇怪奉献及其相互作用承担。</p><p>特别是，巴菲特决定将其活动限于少数种类并最大化对它们的关注，并50年如此，是一个超级成功。巴菲特成功的原因与罗杰·费德勒擅长网球相同。</p><p>巴菲特实际上使用了著名篮球教练约翰·伍登的获胜方法，伍登在学会将几乎所有上场时间分配给七个最佳球员后最常获胜。那样，对手总是面对他的最佳球员，而非次佳。而且，有额外上场时间，最佳球员比正常提高更多。</p><p>而巴菲特远超伍登，因为在他的情况下技能行使集中在一个人身上，而非七个，且他的技能在50年间随着年龄增长而提高提高，而非像篮球运动员的技能那样恶化。</p><p>此外，通过将如此大的权力和权威集中于重要子公司的常任CEO，巴菲特也在那里创造了强大的伍登式效应。这种效应增强了CEO的技能和子公司的成就。</p><p>然后，随着伯克希尔系统赋予许多子公司及其CEO非常渴望的自主权，伯克希尔变得成功和知名，这些结果吸引更多更好的子公司进入伯克希尔，以及更好的CEO。</p><p>而更好的子公司和CEO然后需要总部更少关注，创造了常被称为&quot;良性循环&quot;的东西。</p><p>伯克希尔始终将意外险保险人作为重要子公司效果如何？</p><p>极好。伯克希尔的雄心不合理极端，即便如此，它得到了它想要的。</p><p>意外险保险人常投资于金额大致相当于其股东权益的普通股，伯克希尔的保险子公司也是如此。过去50年标普500指数产生了约10%税前年回报，创造了重要的顺风。</p><p>而且，在巴菲特时代的早期几十年，伯克希尔保险子公司内的普通股远超指数，正如巴菲特预期。后来，当伯克希尔持股的大规模和所得税考虑导致跑赢指数的部分回报消退至微不足道（也许不是永远），其他更好的优势来了。阿吉特·贾恩从无到有创建了巨大的再保险业务，产生了大量&quot;浮存金&quot;和大量承保收益。GEICO全部进入伯克希尔，随后GEICO市场份额翻了两番。伯克希尔其余保险业务大幅改善，主要靠声誉优势、承保纪律、寻找并待在好利基以及招募和留住杰出人才。</p><p>后来，随着伯克希尔几乎独特且相当可靠的企业个性和大规变得知名，其保险子公司获得并抓住了许多他人不可得的有吸引力的购买私募发行证券的机会。这些证券大多有固定期限，产生了杰出结果。</p><p>伯克希尔在保险方面的惊人结果并非自然结果。通常，意外险保险业务产生平庸结果，即使管理非常好。这种结果没什么用。伯克希尔更好的结果如此惊人巨大，我相信如果巴菲特现在回到小基础同时保留聪明并恢复青春，他现在将无法重现它。</p><p>伯克希尔因是分散企业集团而受损吗？不，其机会因运营区域拓宽而有益扩大。其他地方常见的坏影响被巴菲特的技能防止。</p><p>伯克希尔为何偏好用现金而非自身股票购买公司？嗯，很难获得与放弃的一样有价值的伯克希尔股票交换的东西。</p><p>伯克希尔收购保险以外业务为何对伯克希尔股东运作如此良好，而此类收购的正常结果对收购方股东不利？</p><p>嗯，伯克希尔设计上有方法论优势补充其更好机会。它从未有压力购买的&quot;收购部门&quot;等效物。它从未依赖肯定偏向交易的&quot;帮手&quot;建议。且巴菲特在克制自欺的同时，他比大多数企业高管更了解商业什么有效什么无效，得益于他作为被动投资者的长期经验。最后，即使当伯克希尔获得比大多数好得多的机会，巴菲特常展示几乎非人的耐心，很少购买。例如，在他控制伯克希尔的头十年，巴菲特看到一项业务（纺织）接近死亡，两项新业务进来，净增一项。</p><p>巴菲特领导下伯克希尔犯的大错是什么？嗯，虽然作为错误很常见，几乎所有巨大错误都是未进行购买，包括未购买当时肯定将巨大成功的沃尔玛股票。遗漏错误非常重要。伯克希尔的净资产现在将至少比现在高500亿美元，如果它抓住了几次它不够聪明未能识别为几乎确定事物的机会。</p><p>我清单上的倒数第二项任务是：预测如果巴菲特不久离开，伯克希尔的异常好结果是否会继续。</p><p>答案是肯定的。伯克希尔在其子公司中拥有大量业务势头，建立在大量持久竞争优势上。</p><p>此外，其铁路和公用事业子公司现在提供了大量投资新固定资产的理想机会。许多子公司现在正进行明智的&quot;补强&quot;收购。</p><p>只要伯克希尔系统大部分保持到位，现有的综合势头和机会如此巨大，伯克希尔几乎肯定将在很长时间内保持优于正常公司，即使(1)巴菲特明天离开，(2)其继任者仅有中等能力，(3)伯克希尔不再购买大企业。</p><p>但在巴菲特很快离开的假设下，其继任者不会&quot;仅有中等能力&quot;。例如，阿吉特·贾恩和格雷格·阿贝尔是证明表现者，可能被低估描述为&quot;世界级&quot;。&quot;世界领先&quot;是我会选择的描述。在某些重要方面，每位都是比巴菲特更好的企业高管。</p><p>且我相信贾恩和阿贝尔都不会(1)离开伯克希尔，无论他人出价什么，或(2)渴望伯克希尔系统大变。</p><p>我也不认为巴菲特离开后理想的新企业购买会结束。随着伯克希尔现在如此之大和行动主义时代来临，我认为一些理想的收购机会将到来，伯克希尔600亿美元现金将建设性减少。</p><p>我的最后一项任务是考虑伯克希尔过去50年的伟大结果是否有别处可能证明有用的含义。</p><p>答案显然是肯定的。在巴菲特早期，伯克希尔有巨大任务：将微小藏货转变为大而有用的公司。它通过避免官僚主义和长期依赖一位不断改进并引入更多像他自己的人的深思熟虑领导者解决了这个问题。</p><p>将其与典型大公司系统比较：总部大量官僚，一长串约59岁进来的CEO，很少暂停安静思考，很快被固定退休年龄强制退出。</p><p>我相信伯克希尔系统的版本应更常在别处尝试，官僚主义的最坏属性应更常像它们如此相似的癌症那样对待。官僚主义修复的一个好例子是乔治·马歇尔创造的，他通过从国会获得在选择将军时忽略资历的权利帮助赢得二战。</p><p>真诚地，</p><p><strong>查尔斯·T·芒格</strong></p>',469)])])}const l=d(a,[["render",n]]);export{i as __pageData,l as default};
